pragma solidity >=0.7.0;

import "@openzeppelin/contracts-upgradeable/math/SafeMathUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/PausableUpgradeable.sol";
import "./interfaces/ISTokens.sol";
import "./interfaces/IUTokens.sol";
import "./interfaces/ILiquidStaking.sol";
import "./libraries/FullMath.sol";

contract LiquidStakingV2 is
	ILiquidStaking,
	PausableUpgradeable,
	AccessControlUpgradeable
{
	using SafeMathUpgradeable for uint256;
	using FullMath for uint256;


	IUTokens public _uTokens;
	ISTokens public _sTokens;


	uint256 private _minStake;
	uint256 private _minUnstake;
	uint256 private _stakeFee;
	uint256 private _unstakeFee;
	uint256 private _valueDivisor;


	bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");


	uint256 private _unstakingLockTime;
	uint256 private _epochInterval;
	uint256 private _unstakeEpoch;
	uint256 private _unstakeEpochPrevious;


	mapping(address => uint256[]) private _unstakingExpiration;


	mapping(address => uint256[]) private _unstakingAmount;


	mapping(address => uint256) internal _withdrawCounters;


	function initialize(
		address uAddress,
		address sAddress,
		address pauserAddress,
		uint256 unstakingLockTime,
		uint256 epochInterval,
		uint256 valueDivisor
	) public virtual initializer {
		__AccessControl_init();
		__Pausable_init();
		_setupRole(DEFAULT_ADMIN_ROLE, _msgSender());
		_setupRole(PAUSER_ROLE, pauserAddress);
		setUTokensContract(uAddress);
		setSTokensContract(sAddress);
		setUnstakingLockTime(unstakingLockTime);
		setMinimumValues(1, 1);
		_valueDivisor = valueDivisor;
		setUnstakeEpoch(block.timestamp, block.timestamp, epochInterval);
	}


	function setFees(uint256 stakeFee, uint256 unstakeFee)
		public
		virtual
		returns (bool success)
	{
		require(hasRole(DEFAULT_ADMIN_ROLE, _msgSender()), "LQ1");


		require(
			(stakeFee <= _valueDivisor.mul(100) || stakeFee == 0) &&
				(unstakeFee <= _valueDivisor.mul(100) || unstakeFee == 0),
			"LQ2"
		);
		_stakeFee = stakeFee;
		_unstakeFee = unstakeFee;
		emit SetFees(stakeFee, unstakeFee);
		return true;
	}


	function setUnstakingLockTime(uint256 unstakingLockTime)
		public
		virtual
		returns (bool success)
	{
		require(hasRole(DEFAULT_ADMIN_ROLE, _msgSender()), "LQ3");
		_unstakingLockTime = unstakingLockTime;
		emit SetUnstakingLockTime(unstakingLockTime);
		return true;
	}


	function getStakeUnstakeProps()
		public
		view
		virtual
		returns (
			uint256 stakeFee,
			uint256 unstakeFee,
			uint256 minStake,
			uint256 minUnstake,
			uint256 valueDivisor,
			uint256 epochInterval,
			uint256 unstakeEpoch,
			uint256 unstakeEpochPrevious,
			uint256 unstakingLockTime
		)
	{
		stakeFee = _stakeFee;
		unstakeFee = _unstakeFee;
		minStake = _minStake;
		minUnstake = _minStake;
		valueDivisor = _valueDivisor;
		epochInterval = _epochInterval;
		unstakeEpoch = _unstakeEpoch;
		unstakeEpochPrevious = _unstakeEpochPrevious;
		unstakingLockTime = _unstakingLockTime;
	}


	function setMinimumValues(uint256 minStake, uint256 minUnstake)
		public
		virtual
		returns (bool success)
	{
		require(hasRole(DEFAULT_ADMIN_ROLE, _msgSender()), "LQ4");
		require(minStake >= 1, "LQ5");
		require(minUnstake >= 1, "LQ6");
		_minStake = minStake;
		_minUnstake = minUnstake;
		emit SetMinimumValues(minStake, minUnstake);
		return true;
	}


	function setUnstakeEpoch(
		uint256 unstakeEpoch,
		uint256 unstakeEpochPrevious,
		uint256 epochInterval
	) public virtual returns (bool success) {
		require(hasRole(DEFAULT_ADMIN_ROLE, _msgSender()), "LQ7");
		require(unstakeEpochPrevious <= unstakeEpoch, "LQ8");

		if (unstakeEpoch == 0 && epochInterval != 0) revert("LQ9");
		_unstakeEpoch = unstakeEpoch;
		_unstakeEpochPrevious = unstakeEpochPrevious;
		_epochInterval = epochInterval;
		emit SetUnstakeEpoch(unstakeEpoch, unstakeEpochPrevious, epochInterval);
		return true;
	}


	function setUTokensContract(address uAddress) public virtual override {
		require(hasRole(DEFAULT_ADMIN_ROLE, _msgSender()), "LQ10");
		_uTokens = IUTokens(uAddress);
		emit SetUTokensContract(uAddress);
	}


	function setSTokensContract(address sAddress) public virtual override {
		require(hasRole(DEFAULT_ADMIN_ROLE, _msgSender()), "LQ11");
		_sTokens = ISTokens(sAddress);
		emit SetSTokensContract(sAddress);
	}


	function stake(address to, uint256 amount)
		public
		virtual
		override
		whenNotPaused
		returns (bool)
	{

		require(to == _msgSender(), "LQ12");

		uint256 _currentUTokenBalance = _uTokens.balanceOf(to);
		uint256 _stakeFeeAmount = (amount.mulDiv(_stakeFee, _valueDivisor)).div(
			100
		);
		uint256 _finalTokens = amount.add(_stakeFeeAmount);


		require(amount >= _minStake, "LQ13");
		require(_currentUTokenBalance >= _finalTokens, "LQ14");
		emit StakeTokens(to, amount, _finalTokens, block.timestamp);

		_uTokens.burn(to, _finalTokens);

		_sTokens.mint(to, amount);
		return true;
	}


	function unStake(address to, uint256 amount)
		public
		virtual
		override
		whenNotPaused
		returns (bool)
	{

		require(to == _msgSender(), "LQ15");


		uint256 _currentSTokenBalance = _sTokens.balanceOf(to);
		uint256 _unstakeFeeAmount = (amount.mulDiv(_unstakeFee, _valueDivisor))
			.div(100);
		uint256 _finalTokens = amount.add(_unstakeFeeAmount);


		require(amount >= _minUnstake, "LQ18");
		require(_currentSTokenBalance >= _finalTokens, "LQ19");

		_sTokens.burn(to, _finalTokens);
		_unstakingExpiration[to].push(block.timestamp);


		_unstakingAmount[to].push(amount);

		emit UnstakeTokens(to, amount, _finalTokens, block.timestamp);

		return true;
	}


	function getUnstakeEpochMilestone(uint256 _unstakeTimestamp)
		public
		view
		virtual
		override
		returns (uint256 unstakeEpochMilestone)
	{
		if (_unstakeTimestamp == 0) return 0;

		if (
			(_unstakeEpoch == 0 && _unstakeEpochPrevious == 0) ||
			_epochInterval == 0
		) return _unstakeTimestamp;
		if (_unstakeEpoch > _unstakeTimestamp) return (_unstakeEpoch);
		uint256 _referenceStartTime = (_unstakeTimestamp).add(
			_unstakeEpoch.sub(_unstakeEpochPrevious)
		);
		uint256 _timeDiff = _referenceStartTime.sub(_unstakeEpoch);
		unstakeEpochMilestone = (_timeDiff.mod(_epochInterval)).add(
			_referenceStartTime
		);
		return (unstakeEpochMilestone);
	}


	function getUnstakeTime(uint256 _unstakeTimestamp)
		public
		view
		virtual
		override
		returns (
			uint256 unstakeTime,
			uint256 unstakeEpoch,
			uint256 unstakeEpochPrevious
		)
	{
		uint256 _unstakeEpochMilestone = getUnstakeEpochMilestone(
			_unstakeTimestamp
		);
		if (_unstakeEpochMilestone == 0)
			return (0, unstakeEpoch, unstakeEpochPrevious);
		unstakeEpoch = _unstakeEpoch;
		unstakeEpochPrevious = _unstakeEpochPrevious;

		unstakeTime = _unstakeEpochMilestone.add(_unstakingLockTime);
		return (unstakeTime, unstakeEpoch, unstakeEpochPrevious);
	}



	function withdrawUnstakedTokens(address staker)
		public
		virtual
		override
		whenNotPaused
	{
		require(staker == _msgSender(), "LQ20");
		uint256 _withdrawBalance;
		uint256 _unstakingExpirationLength = _unstakingExpiration[staker]
			.length;
		uint256 _counter = _withdrawCounters[staker];
		for (
			uint256 i = _counter;
			i < _unstakingExpirationLength;
			i = i.add(1)
		) {

			(uint256 _getUnstakeTime, , ) = getUnstakeTime(
				_unstakingExpiration[staker][i]
			);
			if (block.timestamp >= _getUnstakeTime) {

				_withdrawBalance = _withdrawBalance.add(
					_unstakingAmount[staker][i]
				);
				_unstakingExpiration[staker][i] = 0;
				_unstakingAmount[staker][i] = 0;
				_withdrawCounters[staker] = _withdrawCounters[staker].add(1);
			}
		}

		require(_withdrawBalance > 0, "LQ21");
		emit WithdrawUnstakeTokens(staker, _withdrawBalance, block.timestamp);
		_uTokens.mint(staker, _withdrawBalance);
	}


	function getTotalUnbondedTokens(address staker)
		public
		view
		virtual
		override
		returns (uint256 unbondingTokens)
	{
		uint256 _unstakingExpirationLength = _unstakingExpiration[staker]
			.length;
		uint256 _counter = _withdrawCounters[staker];
		for (
			uint256 i = _counter;
			i < _unstakingExpirationLength;
			i = i.add(1)
		) {

			(uint256 _getUnstakeTime, , ) = getUnstakeTime(
				_unstakingExpiration[staker][i]
			);
			if (block.timestamp >= _getUnstakeTime) {

				unbondingTokens = unbondingTokens.add(
					_unstakingAmount[staker][i]
				);
			}
		}
		return unbondingTokens;
	}


	function getTotalUnbondingTokens(address staker)
		public
		view
		virtual
		override
		returns (uint256 unbondingTokens)
	{
		uint256 _unstakingExpirationLength = _unstakingExpiration[staker]
			.length;
		uint256 _counter = _withdrawCounters[staker];
		for (
			uint256 i = _counter;
			i < _unstakingExpirationLength;
			i = i.add(1)
		) {

			(uint256 _getUnstakeTime, , ) = getUnstakeTime(
				_unstakingExpiration[staker][i]
			);
			if (block.timestamp < _getUnstakeTime) {

				unbondingTokens = unbondingTokens.add(
					_unstakingAmount[staker][i]
				);
			}
		}
		return unbondingTokens;
	}


	function pause() public virtual returns (bool success) {
		require(hasRole(PAUSER_ROLE, _msgSender()), "LQ22");
		_pause();
		return true;
	}


	function unpause() public virtual returns (bool success) {
		require(hasRole(PAUSER_ROLE, _msgSender()), "LQ23");
		_unpause();
		return true;
	}
}

pragma solidity >=0.7.0;

import "@openzeppelin/contracts-upgradeable/token/ERC20/ERC20Upgradeable.sol";
import "@openzeppelin/contracts-upgradeable/math/SafeMathUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/PausableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/EnumerableSetUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "./interfaces/ISTokens.sol";
import "./interfaces/IUTokens.sol";
import "./interfaces/IHolder.sol";
import "./libraries/FullMath.sol";

contract STokensV2 is
	ERC20Upgradeable,
	ISTokens,
	PausableUpgradeable,
	AccessControlUpgradeable
{
	using SafeMathUpgradeable for uint256;
	using FullMath for uint256;
	using EnumerableSetUpgradeable for EnumerableSetUpgradeable.AddressSet;


	bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");



	EnumerableSetUpgradeable.AddressSet private _whitelistedAddresses;

	mapping(address => address) public _holderContractAddress;

	mapping(address => address) public _lpContractAddress;



	mapping(address => uint256) public _lastHolderRewardTimestamp;


	address public _liquidStakingContract;

	IUTokens public _uTokens;


	uint256[] private _rewardRate;
	uint256[] private _lastMovingRewardTimestamp;
	uint256 private _valueDivisor;
	mapping(address => uint256) private _lastUserRewardTimestamp;


	function initialize(
		address uaddress,
		address pauserAddress,
		uint256 rewardRate,
		uint256 valueDivisor
	) public virtual initializer {
		__ERC20_init("pSTAKE Staked ATOM", "stkATOM");
		__AccessControl_init();
		__Pausable_init();
		_setupRole(DEFAULT_ADMIN_ROLE, _msgSender());
		_setupRole(PAUSER_ROLE, pauserAddress);
		setUTokensContract(uaddress);
		_valueDivisor = valueDivisor;
		require(rewardRate <= _valueDivisor.mul(100), "ST1");
		_rewardRate.push(rewardRate);
		_lastMovingRewardTimestamp.push(block.timestamp);
		_setupDecimals(6);
	}


	function isContractWhitelisted(address whitelistedAddress)
		public
		view
		virtual
		override
		returns (bool result)
	{
		result = _whitelistedAddresses.contains(whitelistedAddress);
		return result;
	}


	function getHolderData(address whitelistedAddress)
		public
		view
		virtual
		override
		returns (
			address holderAddress,
			address lpAddress,
			uint256 lastHolderRewardTimestamp
		)
	{

		holderAddress = _holderContractAddress[whitelistedAddress];
		lpAddress = _lpContractAddress[whitelistedAddress];
		lastHolderRewardTimestamp = _lastHolderRewardTimestamp[
			whitelistedAddress
		];
	}



	function setRewardRate(uint256 rewardRate)
		public
		virtual
		override
		returns (bool success)
	{


		require(rewardRate <= _valueDivisor.mul(100), "ST17");
		require(hasRole(DEFAULT_ADMIN_ROLE, _msgSender()), "ST2");
		_rewardRate.push(rewardRate);
		_lastMovingRewardTimestamp.push(block.timestamp);
		emit SetRewardRate(rewardRate);

		return true;
	}


	function getRewardRate()
		public
		view
		virtual
		returns (uint256[] memory rewardRate, uint256 valueDivisor)
	{
		rewardRate = _rewardRate;
		valueDivisor = _valueDivisor;
	}


	function getLastUserRewardTimestamp(address to)
		public
		view
		virtual
		returns (uint256 lastUserRewardTimestamp)
	{
		lastUserRewardTimestamp = _lastUserRewardTimestamp[to];
	}


	function mint(address to, uint256 tokens)
		public
		virtual
		override
		returns (bool)
	{
		require(_msgSender() == _liquidStakingContract, "ST3");
		_mint(to, tokens);
		return true;
	}


	function burn(address from, uint256 tokens)
		public
		virtual
		override
		returns (bool)
	{
		require(_msgSender() == _liquidStakingContract, "ST4");
		_burn(from, tokens);
		return true;
	}


	function _calculatePendingRewards(
		uint256 principal,
		uint256 lastRewardTimestamp
	) internal view returns (uint256 pendingRewards) {
		uint256 _index;
		uint256 _rewardBlocks;
		uint256 _simpleInterestOfInterval;
		uint256 _temp;

		if (principal == 0 || block.timestamp.sub(lastRewardTimestamp) == 0)
			return 0;

		uint256 _lastMovingRewardLength = _lastMovingRewardTimestamp.length.sub(
			1
		);
		for (_index = _lastMovingRewardLength; _index >= 0; ) {

			if (_index < _lastMovingRewardTimestamp.length.sub(1)) {
				if (_lastMovingRewardTimestamp[_index] > lastRewardTimestamp) {
					_rewardBlocks = (_lastMovingRewardTimestamp[_index.add(1)])
						.sub(_lastMovingRewardTimestamp[_index]);
					_temp = principal.mulDiv(_rewardRate[_index], 100);
					_simpleInterestOfInterval = _temp.mulDiv(
						_rewardBlocks,
						_valueDivisor
					);
					pendingRewards = pendingRewards.add(
						_simpleInterestOfInterval
					);
				} else {
					_rewardBlocks = (_lastMovingRewardTimestamp[_index.add(1)])
						.sub(lastRewardTimestamp);
					_temp = principal.mulDiv(_rewardRate[_index], 100);
					_simpleInterestOfInterval = _temp.mulDiv(
						_rewardBlocks,
						_valueDivisor
					);
					pendingRewards = pendingRewards.add(
						_simpleInterestOfInterval
					);
					break;
				}
			}

			else {
				if (_lastMovingRewardTimestamp[_index] > lastRewardTimestamp) {
					_rewardBlocks = (block.timestamp).sub(
						_lastMovingRewardTimestamp[_index]
					);
					_temp = principal.mulDiv(_rewardRate[_index], 100);
					_simpleInterestOfInterval = _temp.mulDiv(
						_rewardBlocks,
						_valueDivisor
					);
					pendingRewards = pendingRewards.add(
						_simpleInterestOfInterval
					);
				} else {
					_rewardBlocks = (block.timestamp).sub(lastRewardTimestamp);
					_temp = principal.mulDiv(_rewardRate[_index], 100);
					_simpleInterestOfInterval = _temp.mulDiv(
						_rewardBlocks,
						_valueDivisor
					);
					pendingRewards = pendingRewards.add(
						_simpleInterestOfInterval
					);
					break;
				}
			}

			if (_index == 0) break;
			else {
				_index = _index.sub(1);
			}
		}
		return pendingRewards;
	}


	function calculatePendingRewards(address to)
		public
		view
		virtual
		override
		returns (uint256 pendingRewards)
	{

		uint256 _lastRewardTimestamp = _lastUserRewardTimestamp[to];

		uint256 _balance = balanceOf(to);

		pendingRewards = _calculatePendingRewards(
			_balance,
			_lastRewardTimestamp
		);

		return pendingRewards;
	}


	function _calculateRewards(address to) internal returns (uint256) {

		uint256 _reward = calculatePendingRewards(to);



		_lastUserRewardTimestamp[to] = block.timestamp;


		if (_reward > 0) {

			_uTokens.mint(to, _reward);
		}

		emit CalculateRewards(to, _reward, block.timestamp);
		return _reward;
	}


	function calculateRewards(address to)
		public
		virtual
		override
		whenNotPaused
		returns (bool success)
	{
		require(to == _msgSender(), "ST5");
		uint256 reward = _calculateRewards(to);
		emit TriggeredCalculateRewards(to, reward, block.timestamp);
		return true;
	}


	function _calculateHolderRewards(
		address to,
		address from,
		uint256 amount
	) internal returns (uint256 rewards) {



		require(
			_whitelistedAddresses.contains(to) &&
				_holderContractAddress[to] != address(0) &&
				_lpContractAddress[to] != address(0),
			"ST6"
		);
		uint256 _sTokenSupply = IHolder(_holderContractAddress[to])
			.getSTokenSupply(to, from, amount);


		rewards = _calculatePendingRewards(
			_sTokenSupply,
			_lastHolderRewardTimestamp[to]
		);


		_lastHolderRewardTimestamp[to] = block.timestamp;


		if (rewards > 0) {
			_uTokens.mint(_holderContractAddress[to], rewards);
		}

		emit CalculateHolderRewards(to, rewards, block.timestamp);
		return rewards;
	}


	function calculateHolderRewards(
		address to,
		address from,
		uint256 amount
	) public virtual override whenNotPaused returns (bool success) {
		require(to != address(0) && to != address(0), "ST16");
		uint256 rewards = _calculateHolderRewards(to, from, amount);
		emit TriggeredCalculateHolderRewards(to, rewards, block.timestamp);
		return true;
	}


	function _beforeTokenTransfer(
		address from,
		address to,
		uint256 amount
	) internal virtual override {
		require(!paused(), "ST7");
		super._beforeTokenTransfer(from, to, amount);


		if (from == address(0)) {



			if (!_whitelistedAddresses.contains(to)) {
				_calculateRewards(to);
			} else {

				_calculateHolderRewards(to, from, amount);
			}
		}

		if (from != address(0) && !_whitelistedAddresses.contains(from)) {
			if (to == address(0)) {
				_calculateRewards(from);
			}

			if (to != address(0) && !_whitelistedAddresses.contains(to)) {
				_calculateRewards(from);
				_calculateRewards(to);
			}

			if (to != address(0) && _whitelistedAddresses.contains(to)) {
				_calculateRewards(from);

				_calculateHolderRewards(to, from, amount);
			}
		}

		if (from != address(0) && _whitelistedAddresses.contains(from)) {
			if (to == address(0)) {

				_calculateHolderRewards(from, to, amount);
			}

			if (to != address(0) && !_whitelistedAddresses.contains(to)) {

				_calculateHolderRewards(from, to, amount);
				_calculateRewards(to);
			}

			if (to != address(0) && _whitelistedAddresses.contains(to)) {

				_calculateHolderRewards(from, address(0), amount);


				_calculateHolderRewards(to, address(0), amount);
			}
		}
	}


	function setWhitelistedAddress(
		address whitelistedAddress,
		address holderContractAddress,
		address lpContractAddress
	) public virtual returns (bool success) {
		require(hasRole(DEFAULT_ADMIN_ROLE, _msgSender()), "ST8");

		require(whitelistedAddress != address(0), "ST9");

		if (!_whitelistedAddresses.contains(whitelistedAddress))
			_whitelistedAddresses.add(whitelistedAddress);

		_holderContractAddress[whitelistedAddress] = holderContractAddress;
		_lpContractAddress[whitelistedAddress] = lpContractAddress;

		emit SetWhitelistedAddress(
			whitelistedAddress,
			holderContractAddress,
			lpContractAddress,
			block.timestamp
		);
		success = true;
		return success;
	}


	function removeWhitelistedAddress(address whitelistedAddress)
		public
		virtual
		returns (bool success)
	{
		require(hasRole(DEFAULT_ADMIN_ROLE, _msgSender()), "ST10");
		require(whitelistedAddress != address(0), "ST11");

		_whitelistedAddresses.remove(whitelistedAddress);
		address _holderContractAddressLocal = _holderContractAddress[
			whitelistedAddress
		];
		address _lpContractAddressLocal = _lpContractAddress[
			whitelistedAddress
		];


		delete _holderContractAddress[whitelistedAddress];
		delete _lpContractAddress[whitelistedAddress];

		emit RemoveWhitelistedAddress(
			whitelistedAddress,
			_holderContractAddressLocal,
			_lpContractAddressLocal,
			block.timestamp
		);
		success = true;
		return success;
	}


	function setUTokensContract(address uTokenContract)
		public
		virtual
		override
	{
		require(hasRole(DEFAULT_ADMIN_ROLE, _msgSender()), "ST12");
		_uTokens = IUTokens(uTokenContract);
		emit SetUTokensContract(uTokenContract);
	}


	function setLiquidStakingContract(address liquidStakingContract)
		public
		virtual
		override
	{
		require(hasRole(DEFAULT_ADMIN_ROLE, _msgSender()), "ST13");
		_liquidStakingContract = liquidStakingContract;
		emit SetLiquidStakingContract(liquidStakingContract);
	}


	function pause() public virtual returns (bool success) {
		require(hasRole(PAUSER_ROLE, _msgSender()), "ST14");
		_pause();
		return true;
	}


	function unpause() public virtual returns (bool success) {
		require(hasRole(PAUSER_ROLE, _msgSender()), "ST15");
		_unpause();
		return true;
	}
}

pragma solidity 0.7.6;



import "@openzeppelin/contracts/math/SafeMath.sol";

import "../RocketBase.sol";
import "../../interface/RocketVaultInterface.sol";
import "../../interface/RocketVaultWithdrawerInterface.sol";
import "../../interface/deposit/RocketDepositPoolInterface.sol";
import "../../interface/minipool/RocketMinipoolInterface.sol";
import "../../interface/minipool/RocketMinipoolQueueInterface.sol";
import "../../interface/dao/protocol/settings/RocketDAOProtocolSettingsDepositInterface.sol";
import "../../interface/token/RocketTokenRETHInterface.sol";





contract RocketDepositPool is RocketBase, RocketDepositPoolInterface, RocketVaultWithdrawerInterface {


    using SafeMath for uint;


    event DepositReceived(address indexed from, uint256 amount, uint256 time);
    event DepositRecycled(address indexed from, uint256 amount, uint256 time);
    event DepositAssigned(address indexed minipool, uint256 amount, uint256 time);
    event ExcessWithdrawn(address indexed to, uint256 amount, uint256 time);


    constructor(address _rocketStorageAddress) RocketBase(_rocketStorageAddress) {
        version = 1;
    }


    function getBalance() override public view returns (uint256) {
        RocketVaultInterface rocketVault = RocketVaultInterface(getContractAddress("rocketVault"));
        return rocketVault.balanceOf("rocketDepositPool");
    }


    function getExcessBalance() override public view returns (uint256) {

        RocketMinipoolQueueInterface rocketMinipoolQueue = RocketMinipoolQueueInterface(getContractAddress("rocketMinipoolQueue"));
        uint256 minipoolCapacity = rocketMinipoolQueue.getEffectiveCapacity();

        uint256 balance = getBalance();
        if (minipoolCapacity >= balance) { return 0; }
        else { return balance.sub(minipoolCapacity); }
    }



    function receiveVaultWithdrawalETH() override external payable onlyLatestContract("rocketDepositPool", address(this)) onlyLatestContract("rocketVault", msg.sender) {}


    function deposit() override external payable onlyLatestContract("rocketDepositPool", address(this)) {

        RocketDAOProtocolSettingsDepositInterface rocketDAOProtocolSettingsDeposit = RocketDAOProtocolSettingsDepositInterface(getContractAddress("rocketDAOProtocolSettingsDeposit"));
        RocketTokenRETHInterface rocketTokenRETH = RocketTokenRETHInterface(getContractAddress("rocketTokenRETH"));

        require(rocketDAOProtocolSettingsDeposit.getDepositEnabled(), "Deposits into Rocket Pool are currently disabled");
        require(msg.value >= rocketDAOProtocolSettingsDeposit.getMinimumDeposit(), "The deposited amount is less than the minimum deposit size");
        require(getBalance().add(msg.value) <= rocketDAOProtocolSettingsDeposit.getMaximumDepositPoolSize(), "The deposit pool size after depositing exceeds the maximum size");

        rocketTokenRETH.mint(msg.value, msg.sender);

        emit DepositReceived(msg.sender, msg.value, block.timestamp);

        processDeposit();
    }



    function recycleDissolvedDeposit() override external payable onlyLatestContract("rocketDepositPool", address(this)) onlyRegisteredMinipool(msg.sender) {
        emit DepositRecycled(msg.sender, msg.value, block.timestamp);
        processDeposit();
    }



    function recycleWithdrawnDeposit() override external payable onlyLatestContract("rocketDepositPool", address(this)) onlyLatestContract("rocketNetworkWithdrawal", msg.sender) {
        emit DepositRecycled(msg.sender, msg.value, block.timestamp);
        processDeposit();
    }



    function recycleLiquidatedStake() override external payable onlyLatestContract("rocketDepositPool", address(this)) onlyLatestContract("rocketAuctionManager", msg.sender) {
        emit DepositRecycled(msg.sender, msg.value, block.timestamp);
        processDeposit();
    }


    function processDeposit() private {

        RocketDAOProtocolSettingsDepositInterface rocketDAOProtocolSettingsDeposit = RocketDAOProtocolSettingsDepositInterface(getContractAddress("rocketDAOProtocolSettingsDeposit"));
        RocketVaultInterface rocketVault = RocketVaultInterface(getContractAddress("rocketVault"));

        rocketVault.depositEther{value: msg.value}();

        if (rocketDAOProtocolSettingsDeposit.getAssignDepositsEnabled()) { assignDeposits(); }
    }


    function assignDeposits() override public onlyLatestContract("rocketDepositPool", address(this)) {

        RocketDAOProtocolSettingsDepositInterface rocketDAOProtocolSettingsDeposit = RocketDAOProtocolSettingsDepositInterface(getContractAddress("rocketDAOProtocolSettingsDeposit"));
        RocketMinipoolQueueInterface rocketMinipoolQueue = RocketMinipoolQueueInterface(getContractAddress("rocketMinipoolQueue"));
        RocketVaultInterface rocketVault = RocketVaultInterface(getContractAddress("rocketVault"));

        require(rocketDAOProtocolSettingsDeposit.getAssignDepositsEnabled(), "Deposit assignments are currently disabled");


        for (uint256 i = 0; i < rocketDAOProtocolSettingsDeposit.getMaximumDepositAssignments(); ++i) {

            uint256 minipoolCapacity = rocketMinipoolQueue.getNextCapacity();
            if (minipoolCapacity == 0 || getBalance() < minipoolCapacity) { break; }

            address minipoolAddress = rocketMinipoolQueue.dequeueMinipool();
            RocketMinipoolInterface minipool = RocketMinipoolInterface(minipoolAddress);

            rocketVault.withdrawEther(minipoolCapacity);

            minipool.userDeposit{value: minipoolCapacity}();

            emit DepositAssigned(minipoolAddress, minipoolCapacity, block.timestamp);
        }
    }


    function withdrawExcessBalance(uint256 _amount) override external onlyLatestContract("rocketDepositPool", address(this)) onlyLatestContract("rocketTokenRETH", msg.sender) {

        RocketTokenRETHInterface rocketTokenRETH = RocketTokenRETHInterface(getContractAddress("rocketTokenRETH"));
        RocketVaultInterface rocketVault = RocketVaultInterface(getContractAddress("rocketVault"));

        require(_amount <= getExcessBalance(), "Insufficient excess balance for withdrawal");

        rocketVault.withdrawEther(_amount);

        rocketTokenRETH.depositExcess{value: _amount}();

        emit ExcessWithdrawn(msg.sender, _amount, block.timestamp);
    }

}

pragma solidity 0.6.10;
pragma experimental ABIEncoderV2;

import "./ConstantsHolder.sol";
import "./Nodes.sol";
import "./interfaces/ISkaleDKG.sol";


contract SchainsInternal is Permissions {

    struct Schain {
        string name;
        address owner;
        uint indexInOwnerList;
        uint8 partOfNode;
        uint lifetime;
        uint startDate;
        uint startBlock;
        uint deposit;
        uint64 index;
    }



    mapping (bytes32 => Schain) public schains;

    mapping (bytes32 => bool) public isSchainActive;

    mapping (bytes32 => uint[]) public schainsGroups;

    mapping (bytes32 => mapping (uint => bool)) private _exceptionsForGroups;

    mapping (address => bytes32[]) public schainIndexes;

    mapping (uint => bytes32[]) public schainsForNodes;

    mapping (uint => uint[]) public holesForNodes;

    mapping (bytes32 => uint[]) public holesForSchains;



    bytes32[] public schainsAtSystem;

    uint64 public numberOfSchains;

    uint public sumOfSchainsResources;

    mapping (bytes32 => bool) public usedSchainNames;


    function initializeSchain(
        string calldata name,
        address from,
        uint lifetime,
        uint deposit) external allow("Schains")
    {
        bytes32 schainId = keccak256(abi.encodePacked(name));
        schains[schainId].name = name;
        schains[schainId].owner = from;
        schains[schainId].startDate = block.timestamp;
        schains[schainId].startBlock = block.number;
        schains[schainId].lifetime = lifetime;
        schains[schainId].deposit = deposit;
        schains[schainId].index = numberOfSchains;
        isSchainActive[schainId] = true;
        numberOfSchains++;
        schainsAtSystem.push(schainId);
        usedSchainNames[schainId] = true;
    }


    function createGroupForSchain(
        bytes32 schainId,
        uint numberOfNodes,
        uint8 partOfNode
    )
        external
        allow("Schains")
        returns (uint[] memory)
    {
        ConstantsHolder constantsHolder = ConstantsHolder(contractManager.getContract("ConstantsHolder"));
        schains[schainId].partOfNode = partOfNode;
        if (partOfNode > 0) {
            sumOfSchainsResources = sumOfSchainsResources.add(
                numberOfNodes.mul(constantsHolder.TOTAL_SPACE_ON_NODE()).div(partOfNode)
            );
        }
        return _generateGroup(schainId, numberOfNodes);
    }


    function setSchainIndex(bytes32 schainId, address from) external allow("Schains") {
        schains[schainId].indexInOwnerList = schainIndexes[from].length;
        schainIndexes[from].push(schainId);
    }


    function changeLifetime(bytes32 schainId, uint lifetime, uint deposit) external allow("Schains") {
        schains[schainId].deposit = schains[schainId].deposit.add(deposit);
        schains[schainId].lifetime = schains[schainId].lifetime.add(lifetime);
    }


    function removeSchain(bytes32 schainId, address from) external allow("Schains") {
        isSchainActive[schainId] = false;
        uint length = schainIndexes[from].length;
        uint index = schains[schainId].indexInOwnerList;
        if (index != length.sub(1)) {
            bytes32 lastSchainId = schainIndexes[from][length.sub(1)];
            schains[lastSchainId].indexInOwnerList = index;
            schainIndexes[from][index] = lastSchainId;
        }
        schainIndexes[from].pop();



        for (uint i = 0; i + 1 < schainsAtSystem.length; i++) {
            if (schainsAtSystem[i] == schainId) {
                schainsAtSystem[i] = schainsAtSystem[schainsAtSystem.length.sub(1)];
                break;
            }
        }
        schainsAtSystem.pop();

        delete schains[schainId];
        numberOfSchains--;
    }


    function removeNodeFromSchain(
        uint nodeIndex,
        bytes32 schainHash
    )
        external
        allowThree("NodeRotation", "SkaleDKG", "Schains")
    {
        uint indexOfNode = _findNode(schainHash, nodeIndex);
        uint indexOfLastNode = schainsGroups[schainHash].length.sub(1);

        if (indexOfNode == indexOfLastNode) {
            schainsGroups[schainHash].pop();
        } else {
            delete schainsGroups[schainHash][indexOfNode];
            if (holesForSchains[schainHash].length > 0 && holesForSchains[schainHash][0] > indexOfNode) {
                uint hole = holesForSchains[schainHash][0];
                holesForSchains[schainHash][0] = indexOfNode;
                holesForSchains[schainHash].push(hole);
            } else {
                holesForSchains[schainHash].push(indexOfNode);
            }
        }

        uint schainId = findSchainAtSchainsForNode(nodeIndex, schainHash);
        removeSchainForNode(nodeIndex, schainId);
    }

    function removeNodeFromExceptions(bytes32 schainHash, uint nodeIndex) external allow("Schains") {
        _exceptionsForGroups[schainHash][nodeIndex] = false;
    }


    function deleteGroup(bytes32 schainId) external allow("Schains") {

        ISkaleDKG skaleDKG = ISkaleDKG(contractManager.getContract("SkaleDKG"));
        delete schainsGroups[schainId];
        skaleDKG.deleteChannel(schainId);
    }


    function setException(bytes32 schainId, uint nodeIndex) external allowTwo("Schains", "NodeRotation") {
        _exceptionsForGroups[schainId][nodeIndex] = true;
    }


    function setNodeInGroup(bytes32 schainId, uint nodeIndex) external allowTwo("Schains", "NodeRotation") {
        if (holesForSchains[schainId].length == 0) {
            schainsGroups[schainId].push(nodeIndex);
        } else {
            schainsGroups[schainId][holesForSchains[schainId][0]] = nodeIndex;
            uint min = uint(-1);
            uint index = 0;
            for (uint i = 1; i < holesForSchains[schainId].length; i++) {
                if (min > holesForSchains[schainId][i]) {
                    min = holesForSchains[schainId][i];
                    index = i;
                }
            }
            if (min == uint(-1)) {
                delete holesForSchains[schainId];
            } else {
                holesForSchains[schainId][0] = min;
                holesForSchains[schainId][index] =
                    holesForSchains[schainId][holesForSchains[schainId].length - 1];
                holesForSchains[schainId].pop();
            }
        }
    }

    function removeHolesForSchain(bytes32 schainHash) external allow("Schains") {
        delete holesForSchains[schainHash];
    }


    function getSchains() external view returns (bytes32[] memory) {
        return schainsAtSystem;
    }


    function getSchainsPartOfNode(bytes32 schainId) external view returns (uint8) {
        return schains[schainId].partOfNode;
    }


    function getSchainListSize(address from) external view returns (uint) {
        return schainIndexes[from].length;
    }


    function getSchainIdsByAddress(address from) external view returns (bytes32[] memory) {
        return schainIndexes[from];
    }


    function getSchainIdsForNode(uint nodeIndex) external view returns (bytes32[] memory) {
        return schainsForNodes[nodeIndex];
    }


    function getSchainOwner(bytes32 schainId) external view returns (address) {
        return schains[schainId].owner;
    }


    function isSchainNameAvailable(string calldata name) external view returns (bool) {
        bytes32 schainId = keccak256(abi.encodePacked(name));
        return schains[schainId].owner == address(0) && !usedSchainNames[schainId];
    }


    function isTimeExpired(bytes32 schainId) external view returns (bool) {
        return uint(schains[schainId].startDate).add(schains[schainId].lifetime) < block.timestamp;
    }


    function isOwnerAddress(address from, bytes32 schainId) external view returns (bool) {
        return schains[schainId].owner == from;
    }


    function isSchainExist(bytes32 schainId) external view returns (bool) {
        return keccak256(abi.encodePacked(schains[schainId].name)) != keccak256(abi.encodePacked(""));
    }


    function getSchainName(bytes32 schainId) external view returns (string memory) {
        return schains[schainId].name;
    }


    function getActiveSchain(uint nodeIndex) external view returns (bytes32) {
        for (uint i = schainsForNodes[nodeIndex].length; i > 0; i--) {
            if (schainsForNodes[nodeIndex][i - 1] != bytes32(0)) {
                return schainsForNodes[nodeIndex][i - 1];
            }
        }
        return bytes32(0);
    }


    function getActiveSchains(uint nodeIndex) external view returns (bytes32[] memory activeSchains) {
        uint activeAmount = 0;
        for (uint i = 0; i < schainsForNodes[nodeIndex].length; i++) {
            if (schainsForNodes[nodeIndex][i] != bytes32(0)) {
                activeAmount++;
            }
        }

        uint cursor = 0;
        activeSchains = new bytes32[](activeAmount);
        for (uint i = schainsForNodes[nodeIndex].length; i > 0; i--) {
            if (schainsForNodes[nodeIndex][i - 1] != bytes32(0)) {
                activeSchains[cursor++] = schainsForNodes[nodeIndex][i - 1];
            }
        }
    }


    function getNumberOfNodesInGroup(bytes32 schainId) external view returns (uint) {
        return schainsGroups[schainId].length;
    }


    function getNodesInGroup(bytes32 schainId) external view returns (uint[] memory) {
        return schainsGroups[schainId];
    }


    function getNodeIndexInGroup(bytes32 schainId, uint nodeId) external view returns (uint) {
        for (uint index = 0; index < schainsGroups[schainId].length; index++) {
            if (schainsGroups[schainId][index] == nodeId) {
                return index;
            }
        }
        return schainsGroups[schainId].length;
    }


    function isAnyFreeNode(bytes32 schainId) external view returns (bool) {
        Nodes nodes = Nodes(contractManager.getContract("Nodes"));
        uint8 space = schains[schainId].partOfNode;
        uint[] memory nodesWithFreeSpace = nodes.getNodesWithFreeSpace(space);
        for (uint i = 0; i < nodesWithFreeSpace.length; i++) {
            if (_isCorrespond(schainId, nodesWithFreeSpace[i])) {
                return true;
            }
        }
        return false;
    }


    function checkException(bytes32 schainId, uint nodeIndex) external view returns (bool) {
        return _exceptionsForGroups[schainId][nodeIndex];
    }

    function checkHoleForSchain(bytes32 schainHash, uint indexOfNode) external view returns (bool) {
        for (uint i = 0; i < holesForSchains[schainHash].length; i++) {
            if (holesForSchains[schainHash][i] == indexOfNode) {
                return true;
            }
        }
        return false;
    }

    function initialize(address newContractsAddress) public override initializer {
        Permissions.initialize(newContractsAddress);

        numberOfSchains = 0;
        sumOfSchainsResources = 0;
    }


    function addSchainForNode(uint nodeIndex, bytes32 schainId) public allowTwo("Schains", "NodeRotation") {
        if (holesForNodes[nodeIndex].length == 0) {
            schainsForNodes[nodeIndex].push(schainId);
        } else {
            schainsForNodes[nodeIndex][holesForNodes[nodeIndex][0]] = schainId;
            uint min = uint(-1);
            uint index = 0;
            for (uint i = 1; i < holesForNodes[nodeIndex].length; i++) {
                if (min > holesForNodes[nodeIndex][i]) {
                    min = holesForNodes[nodeIndex][i];
                    index = i;
                }
            }
            if (min == uint(-1)) {
                delete holesForNodes[nodeIndex];
            } else {
                holesForNodes[nodeIndex][0] = min;
                holesForNodes[nodeIndex][index] = holesForNodes[nodeIndex][holesForNodes[nodeIndex].length - 1];
                holesForNodes[nodeIndex].pop();
            }
        }
    }


    function removeSchainForNode(uint nodeIndex, uint schainIndex)
        public
        allowThree("NodeRotation", "SkaleDKG", "Schains")
    {
        uint length = schainsForNodes[nodeIndex].length;
        if (schainIndex == length.sub(1)) {
            schainsForNodes[nodeIndex].pop();
        } else {
            schainsForNodes[nodeIndex][schainIndex] = bytes32(0);
            if (holesForNodes[nodeIndex].length > 0 && holesForNodes[nodeIndex][0] > schainIndex) {
                uint hole = holesForNodes[nodeIndex][0];
                holesForNodes[nodeIndex][0] = schainIndex;
                holesForNodes[nodeIndex].push(hole);
            } else {
                holesForNodes[nodeIndex].push(schainIndex);
            }
        }
    }


    function getLengthOfSchainsForNode(uint nodeIndex) public view returns (uint) {
        return schainsForNodes[nodeIndex].length;
    }


    function findSchainAtSchainsForNode(uint nodeIndex, bytes32 schainId) public view returns (uint) {
        uint length = getLengthOfSchainsForNode(nodeIndex);
        for (uint i = 0; i < length; i++) {
            if (schainsForNodes[nodeIndex][i] == schainId) {
                return i;
            }
        }
        return length;
    }

    function isEnoughNodes(bytes32 schainId) public view returns (uint[] memory result) {
        Nodes nodes = Nodes(contractManager.getContract("Nodes"));
        uint8 space = schains[schainId].partOfNode;
        uint[] memory nodesWithFreeSpace = nodes.getNodesWithFreeSpace(space);
        uint counter = 0;
        for (uint i = 0; i < nodesWithFreeSpace.length; i++) {
            if (!_isCorrespond(schainId, nodesWithFreeSpace[i])) {
                counter++;
            }
        }
        if (counter < nodesWithFreeSpace.length) {
            result = new uint[](nodesWithFreeSpace.length.sub(counter));
            counter = 0;
            for (uint i = 0; i < nodesWithFreeSpace.length; i++) {
                if (_isCorrespond(schainId, nodesWithFreeSpace[i])) {
                    result[counter] = nodesWithFreeSpace[i];
                    counter++;
                }
            }
        }
    }


    function _generateGroup(bytes32 schainId, uint numberOfNodes) private returns (uint[] memory nodesInGroup) {
        Nodes nodes = Nodes(contractManager.getContract("Nodes"));
        uint8 space = schains[schainId].partOfNode;
        nodesInGroup = new uint[](numberOfNodes);

        uint[] memory possibleNodes = isEnoughNodes(schainId);
        require(possibleNodes.length >= nodesInGroup.length, "Not enough nodes to create Schain");
        uint ignoringTail = 0;
        uint random = uint(keccak256(abi.encodePacked(uint(blockhash(block.number.sub(1))), schainId)));

        for (uint i = 0; i < nodesInGroup.length; ++i) {
            uint index = random % (possibleNodes.length.sub(ignoringTail));
            uint node = possibleNodes[index];
            nodesInGroup[i] = node;
            _swap(possibleNodes, index, possibleNodes.length.sub(ignoringTail).sub(1));
            ++ignoringTail;

            _exceptionsForGroups[schainId][node] = true;
            addSchainForNode(node, schainId);
            require(nodes.removeSpaceFromNode(node, space), "Could not remove space from Node");
        }


        schainsGroups[schainId] = nodesInGroup;
    }

    function _isCorrespond(bytes32 schainId, uint nodeIndex) private view returns (bool) {
        Nodes nodes = Nodes(contractManager.getContract("Nodes"));
        return !_exceptionsForGroups[schainId][nodeIndex] && nodes.isNodeActive(nodeIndex);
    }


    function _swap(uint[] memory array, uint index1, uint index2) private pure {
        uint buffer = array[index1];
        array[index1] = array[index2];
        array[index2] = buffer;
    }


    function _findNode(bytes32 schainId, uint nodeIndex) private view returns (uint) {
        uint[] memory nodesInGroup = schainsGroups[schainId];
        uint index;
        for (index = 0; index < nodesInGroup.length; index++) {
            if (nodesInGroup[index] == nodeIndex) {
                return index;
            }
        }
        return index;
    }

}

pragma solidity ^0.5.3;
pragma experimental ABIEncoderV2;

import "@openzeppelin/contracts/introspection/IERC1820Registry.sol";
import "@openzeppelin/contracts/token/ERC777/IERC777Recipient.sol";

import "../Permissions.sol";
import "../interfaces/delegation/IHolderDelegation.sol";
import "../interfaces/delegation/IValidatorDelegation.sol";
import "./DelegationRequestManager.sol";
import "./ValidatorService.sol";
import "./DelegationController.sol";
import "./Distributor.sol";
import "./SkaleBalances.sol";
import "./TokenState.sol";
import "./TimeHelpers.sol";


contract DelegationService is Permissions, IHolderDelegation, IValidatorDelegation, IERC777Recipient {

    event DelegationRequestIsSent(
        uint delegationId
    );

    event ValidatorRegistered(
        uint validatorId
    );

    IERC1820Registry private _erc1820 = IERC1820Registry(0x1820a4B7618BdE71Dce8cdc73aAB6C95905faD24);
    uint private _launchTimestamp;

    constructor(address newContractsAddress) Permissions(newContractsAddress) public {
        _launchTimestamp = now;
        _erc1820.setInterfaceImplementer(address(this), keccak256("ERC777TokensRecipient"), address(this));
    }

    function requestUndelegation(uint delegationId) external {
        TokenState tokenState = TokenState(contractManager.getContract("TokenState"));
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));

        require(
            delegationController.getDelegation(delegationId).holder == msg.sender,
            "Can't request undelegation because sender is not a holder");

        tokenState.requestUndelegation(delegationId);
    }


    function acceptPendingDelegation(uint delegationId) external {
        DelegationRequestManager delegationRequestManager = DelegationRequestManager(
            contractManager.getContract("DelegationRequestManager")
        );
        delegationRequestManager.acceptRequest(delegationId, msg.sender);
    }

    function getDelegationsByHolder(TokenState.State state) external returns (uint[] memory) {
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));
        return delegationController.getDelegationsByHolder(msg.sender, state);
    }

    function getDelegationsForValidator(TokenState.State state) external returns (uint[] memory) {
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));
        return delegationController.getDelegationsForValidator(msg.sender, state);
    }

    function setMinimumDelegationAmount(uint amount) external {
        revert("Not implemented");
    }


    function listDelegationRequests() external returns (uint[] memory) {
        revert("Not implemented");
    }


    function slash(uint validatorId, uint amount) external allow("SkaleDKG") {
        ValidatorService validatorService = ValidatorService(contractManager.getContract("ValidatorService"));
        require(validatorService.validatorExists(validatorId), "Validator does not exist");

        Distributor distributor = Distributor(contractManager.getContract("Distributor"));
        TokenState tokenState = TokenState(contractManager.getContract("TokenState"));

        Distributor.Share[] memory shares = distributor.distributePenalties(validatorId, amount);
        for (uint i = 0; i < shares.length; ++i) {
            tokenState.slash(shares[i].delegationId, shares[i].amount);
        }
    }

    function forgive(address wallet, uint amount) external onlyOwner() {
        TokenState tokenState = TokenState(contractManager.getContract("TokenState"));
        tokenState.forgive(wallet, amount);
    }


    function getDelegatedAmount(uint validatorId) external returns (uint) {
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));
        return delegationController.getDelegationsTotal(validatorId);
    }

    function setMinimumStakingRequirement(uint amount) external onlyOwner() {
        revert("Not implemented");
    }


    function delegate(
        uint validatorId,
        uint amount,
        uint delegationPeriod,
        string calldata info
    )
        external
    {
        DelegationRequestManager delegationRequestManager = DelegationRequestManager(
            contractManager.getContract("DelegationRequestManager")
        );
        uint delegationId = delegationRequestManager.createRequest(
            msg.sender,
            validatorId,
            amount,
            delegationPeriod,
            info
        );
        emit DelegationRequestIsSent(delegationId);
    }

    function cancelPendingDelegation(uint delegationId) external {
        DelegationRequestManager delegationRequestManager = DelegationRequestManager(
            contractManager.getContract("DelegationRequestManager")
        );
        delegationRequestManager.cancelRequest(delegationId, msg.sender);
    }

    function getAllDelegationRequests() external returns(uint[] memory) {
        revert("Not implemented");
    }

    function getDelegationRequestsForValidator(uint validatorId) external returns (uint[] memory) {
        revert("Not implemented");
    }


    function registerValidator(
        string calldata name,
        string calldata description,
        uint feeRate,
        uint minimumDelegationAmount
    )
        external returns (uint validatorId)
    {
        ValidatorService validatorService = ValidatorService(contractManager.getContract("ValidatorService"));
        validatorId = validatorService.registerValidator(
            name,
            msg.sender,
            description,
            feeRate,
            minimumDelegationAmount
        );
        emit ValidatorRegistered(validatorId);
    }

    function linkNodeAddress(address nodeAddress) external {
        ValidatorService validatorService = ValidatorService(contractManager.getContract("ValidatorService"));
        validatorService.linkNodeAddress(msg.sender, nodeAddress);
    }

    function unlinkNodeAddress(address nodeAddress) external {
        ValidatorService validatorService = ValidatorService(contractManager.getContract("ValidatorService"));
        validatorService.unlinkNodeAddress(msg.sender, nodeAddress);
    }

    function unregisterValidator(uint validatorId) external {
        revert("Not implemented");
    }


    function getBondAmount(uint validatorId) external returns (uint amount) {
        revert("Not implemented");
    }

    function setValidatorName(string calldata newName) external {
        revert("Not implemented");
    }

    function setValidatorDescription(string calldata description) external {
        revert("Not implemented");
    }

    function requestForNewAddress(address newAddress) external {
        ValidatorService(contractManager.getContract("ValidatorService")).requestForNewAddress(msg.sender, newAddress);
    }

    function confirmNewAddress(uint validatorId) external {
        ValidatorService validatorService = ValidatorService(contractManager.getContract("ValidatorService"));
        ValidatorService.Validator memory validator = validatorService.getValidator(validatorId);

        require(
            validator.requestedAddress == msg.sender,
            "The validator cannot be changed because it isn't the actual owner"
        );

        validatorService.confirmNewAddress(msg.sender, validatorId);
    }

    function getValidators() external view returns (uint[] memory validatorIds) {
        ValidatorService validatorService = ValidatorService(contractManager.getContract("ValidatorService"));
        validatorIds = new uint[](validatorService.numberOfValidators());
        for (uint i = 0; i < validatorIds.length; ++i) {
            validatorIds[i] = i + 1;
        }
    }

    function withdrawBounty(address bountyCollectionAddress, uint amount) external {
        SkaleBalances skaleBalances = SkaleBalances(contractManager.getContract("SkaleBalances"));
        skaleBalances.withdrawBalance(msg.sender, bountyCollectionAddress, amount);
    }

    function getEarnedBountyAmount() external returns (uint) {
        SkaleBalances skaleBalances = SkaleBalances(contractManager.getContract("SkaleBalances"));
        return skaleBalances.getBalance(msg.sender);
    }


    function deleteNode(uint nodeIndex) external {
        revert("Not implemented");
    }


    function lock(address wallet, uint amount) external allow("TokenSaleManager") {
        SkaleToken skaleToken = SkaleToken(contractManager.getContract("SkaleToken"));
        TokenState tokenState = TokenState(contractManager.getContract("TokenState"));

        require(skaleToken.balanceOf(wallet) >= tokenState.getPurchasedAmount(wallet) + amount, "Not enough founds");

        tokenState.sold(wallet, amount);
    }

    function getLockedOf(address wallet) external returns (uint) {
        TokenState tokenState = TokenState(contractManager.getContract("TokenState"));
        return tokenState.getLockedCount(wallet);
    }

    function getDelegatedOf(address wallet) external returns (uint) {
        TokenState tokenState = TokenState(contractManager.getContract("TokenState"));
        return tokenState.getDelegatedCount(wallet);
    }

    function getSlashedOf(address wallet) external returns (uint) {
        TokenState tokenState = TokenState(contractManager.getContract("TokenState"));
        return tokenState.getSlashedAmount(wallet);
    }

    function setLaunchTimestamp(uint timestamp) external onlyOwner {
        _launchTimestamp = timestamp;
    }

    function tokensReceived(
        address operator,
        address from,
        address to,
        uint256 amount,
        bytes calldata userData,
        bytes calldata operatorData
    )
        external
        allow("SkaleToken")
    {
        require(userData.length == 32, "Data length is incorrect");
        uint validatorId = abi.decode(userData, (uint));
        distributeBounty(amount, validatorId);
    }



    function distributeBounty(uint amount, uint validatorId) internal {
        ValidatorService validatorService = ValidatorService(contractManager.getContract("ValidatorService"));

        SkaleToken skaleToken = SkaleToken(contractManager.getContract("SkaleToken"));
        Distributor distributor = Distributor(contractManager.getContract("Distributor"));
        SkaleBalances skaleBalances = SkaleBalances(contractManager.getContract("SkaleBalances"));
        TimeHelpers timeHelpers = TimeHelpers(contractManager.getContract("TimeHelpers"));
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));

        Distributor.Share[] memory shares;
        uint fee;
        (shares, fee) = distributor.distributeBounty(validatorId, amount);

        address validatorAddress = validatorService.getValidator(validatorId).validatorAddress;
        skaleToken.send(address(skaleBalances), fee, abi.encode(validatorAddress));
        skaleBalances.lockBounty(validatorAddress, timeHelpers.addMonths(_launchTimestamp, 3));

        for (uint i = 0; i < shares.length; ++i) {
            skaleToken.send(address(skaleBalances), shares[i].amount, abi.encode(shares[i].holder));

            uint created = delegationController.getDelegation(shares[i].delegationId).created;
            uint delegationStarted = timeHelpers.getNextMonthStartFromDate(created);
            skaleBalances.lockBounty(shares[i].holder, timeHelpers.addMonths(delegationStarted, 3));
        }
    }
}

pragma solidity ^0.5.3;
pragma experimental ABIEncoderV2;

import "../Permissions.sol";
import "./DelegationController.sol";
import "./TimeHelpers.sol";



contract TokenState is Permissions {

    enum State {
        PROPOSED,
        ACCEPTED,
        DELEGATED,
        ENDING_DELEGATED,
        COMPLETED
    }


    mapping (uint => State) private _state;


    mapping (uint => uint) private _timelimit;


    mapping (address => uint) private _purchased;

    mapping (address => uint) private _slashed;

    mapping (address => uint) private _totalDelegated;

    mapping (uint => bool) private _isPurchased;


    mapping (address => uint[]) private _endingDelegations;

    constructor(address _contractManager) Permissions(_contractManager) public {
    }

    function getLockedCount(address holder) external returns (uint amount) {
        amount = 0;
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));
        uint[] memory delegationIds = delegationController.getDelegationsByHolder(holder);

        for (uint i = 0; i < delegationIds.length; ++i) {
            uint id = delegationIds[i];
            if (isLocked(getState(id))) {
                amount += delegationController.getDelegation(id).amount;
            }
        }
        return amount + getPurchasedAmount(holder) + this.getSlashedAmount(holder);
    }

    function getDelegatedCount(address holder) external returns (uint amount) {
        amount = 0;
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));
        uint[] memory delegationIds = delegationController.getDelegationsByHolder(holder);
        for (uint i = 0; i < delegationIds.length; ++i) {
            uint id = delegationIds[i];
            if (isDelegated(getState(id))) {
                amount += delegationController.getDelegation(id).amount;
            }
        }
        return amount;
    }

    function sold(address holder, uint amount) external allow("DelegationService") {
        _purchased[holder] += amount;
    }

    function accept(uint delegationId) external allow("DelegationRequestManager") {
        require(getState(delegationId) == State.PROPOSED, "Can't set state to accepted");
        setState(delegationId, State.ACCEPTED);
    }

    function requestUndelegation(uint delegationId) external allow("DelegationService") {
        require(getState(delegationId) == State.DELEGATED, "Can't request undelegation");
        setState(delegationId, State.ENDING_DELEGATED);
    }

    function cancel(uint delegationId) external allow("DelegationRequestManager") returns (State state) {
        require(getState(delegationId) == State.PROPOSED, "Can't cancel delegation request");
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));
        return _cancel(delegationId, delegationController.getDelegation(delegationId));
    }

    function slash(uint delegationId, uint amount) external allow("DelegationService") {
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));
        DelegationController.Delegation memory delegation = delegationController.getDelegation(delegationId);
        uint slashingAmount = amount;
        if (delegation.amount < amount) {

            slashingAmount = delegation.amount;
        }
        _slashed[delegation.holder] += slashingAmount;
        delegationController.setDelegationAmount(delegationId, delegation.amount - slashingAmount);
    }

    function forgive(address wallet, uint amount) external allow("DelegationService") {
        uint forgiveAmount = amount;
        if (amount > _slashed[wallet]) {
            forgiveAmount = _slashed[wallet];
        }
        _slashed[wallet] -= forgiveAmount;
    }

    function getSlashedAmount(address holder) external returns (uint amount) {
        return _slashed[holder];
    }

    function getState(uint delegationId) public returns (State state) {
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));

        require(delegationController.getDelegation(delegationId).holder != address(0), "Delegation does not exists");
        state = _state[delegationId];
        if (state == State.PROPOSED) {
            if (_timelimit[delegationId] == 0) {
                initProposed(delegationId);
            }
            if (now >= _timelimit[delegationId]) {
                state = _cancel(delegationId, delegationController.getDelegation(delegationId));
            }
        } else if (state == State.ACCEPTED) {
            if (now >= _timelimit[delegationId]) {
                state = acceptedToDelegated(delegationId);
                uint validatorId = delegationController.getDelegation(delegationId).validatorId;
                uint amount = delegationController.getDelegation(delegationId).amount;
                delegationController.addDelegationsTotal(validatorId, amount);
            }
        } else if (state == State.ENDING_DELEGATED) {
            if (now >= _timelimit[delegationId]) {
                state = endingDelegatedToUnlocked(delegationId, delegationController.getDelegation(delegationId));
                uint validatorId = delegationController.getDelegation(delegationId).validatorId;
                uint amount = delegationController.getDelegation(delegationId).amount;
                delegationController.subDelegationsTotal(validatorId, amount);
            }
        }
    }

    function getPurchasedAmount(address holder) public returns (uint amount) {

        for (uint i = 0; i < _endingDelegations[holder].length; ++i) {
            getState(_endingDelegations[holder][i]);
        }
        return _purchased[holder];
    }

    function isDelegated(State state) public returns (bool) {
        return state == State.DELEGATED || state == State.ENDING_DELEGATED;
    }



    function setState(uint delegationId, State newState) internal {
        TimeHelpers timeHelpers = TimeHelpers(contractManager.getContract("TimeHelpers"));
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));

        require(newState != State.PROPOSED, "Can't set state to proposed");

        if (newState == State.ACCEPTED) {
            State currentState = getState(delegationId);
            require(currentState == State.PROPOSED, "Can't set state to accepted");

            _state[delegationId] = State.ACCEPTED;
            _timelimit[delegationId] = timeHelpers.getNextMonthStart();
        } else if (newState == State.DELEGATED) {
            revert("Can't set state to delegated");
        } else if (newState == State.ENDING_DELEGATED) {
            require(getState(delegationId) == State.DELEGATED, "Can't set state to ending delegated");
            DelegationController.Delegation memory delegation = delegationController.getDelegation(delegationId);

            _state[delegationId] = State.ENDING_DELEGATED;
            _timelimit[delegationId] = timeHelpers.calculateDelegationEndTime(delegation.created, delegation.delegationPeriod, 3);
            _endingDelegations[delegation.holder].push(delegationId);
        } else {
            revert("Unknown state");
        }
    }

    function initProposed(uint delegationId) internal {
        TimeHelpers timeHelpers = TimeHelpers(contractManager.getContract("TimeHelpers"));
        DelegationController delegationController = DelegationController(contractManager.getContract("DelegationController"));
        DelegationController.Delegation memory delegation = delegationController.getDelegation(delegationId);

        _timelimit[delegationId] = timeHelpers.getNextMonthStartFromDate(delegation.created);
        if (_purchased[delegation.holder] > 0) {
            _isPurchased[delegationId] = true;
            if (_purchased[delegation.holder] > delegation.amount) {
                _purchased[delegation.holder] -= delegation.amount;
            } else {
                _purchased[delegation.holder] = 0;
            }
        } else {
            _isPurchased[delegationId] = false;
        }
    }

    function isLocked(State state) internal returns (bool) {
        return state != State.COMPLETED;
    }

    function proposedToUnlocked(uint delegationId) internal returns (State state) {
        state = State.COMPLETED;
        _state[delegationId] = state;
        _timelimit[delegationId] = 0;
    }

    function acceptedToDelegated(uint delegationId) internal returns (State state) {
        state = State.DELEGATED;
        _state[delegationId] = state;
        _timelimit[delegationId] = 0;
    }

    function purchasedProposedToPurchased(uint delegationId, DelegationController.Delegation memory delegation) internal returns (State state) {
        state = State.COMPLETED;
        _state[delegationId] = state;
        _timelimit[delegationId] = 0;
        _purchased[delegation.holder] += delegation.amount;
    }

    function endingDelegatedToUnlocked(uint delegationId, DelegationController.Delegation memory delegation) internal returns (State state) {
        state = State.COMPLETED;
        _state[delegationId] = state;
        _timelimit[delegationId] = 0;


        uint endingLength = _endingDelegations[delegation.holder].length;
        for (uint i = 0; i < endingLength; ++i) {
            if (_endingDelegations[delegation.holder][i] == delegationId) {
                for (uint j = i; j + 1 < endingLength; ++j) {
                    _endingDelegations[delegation.holder][j] = _endingDelegations[delegation.holder][j+1];
                }
                _endingDelegations[delegation.holder][endingLength - 1] = 0;
                --_endingDelegations[delegation.holder].length;
                break;
            }
        }

        if (_isPurchased[delegationId]) {
            address holder = delegation.holder;
            _totalDelegated[holder] += delegation.amount;
            if (_totalDelegated[holder] >= _purchased[holder]) {
                purchasedToUnlocked(holder);
            }
        }
    }

    function purchasedToUnlocked(address holder) internal {
        _purchased[holder] = 0;
        _totalDelegated[holder] = 0;
    }

    function _cancel(uint delegationId, DelegationController.Delegation memory delegation) internal returns (State state) {
        if (_isPurchased[delegationId]) {
            state = purchasedProposedToPurchased(delegationId, delegation);
        } else {
            state = proposedToUnlocked(delegationId);
        }
    }

}

pragma solidity ^0.8.2;

import "./Ania.sol";

contract AniaStake {
    string public name = "Arkania Protocol Launchpad";
    ArkaniaProtocol public aniaToken;


    address public owner;


    uint256 public apy = 100;


    uint256 public totalStaked = 0;


    struct Stake{
        address user;
        uint256 amount;
        uint256 since;
    }


    struct Staker{
        address user;
        Stake address_stake;
    }


    Staker[] internal stakers;


    mapping(address => uint256) internal stakes;

    constructor(ArkaniaProtocol _aniaToken) payable {
        aniaToken = _aniaToken;


        owner = msg.sender;


        stakers.push();
    }


    function calculateStakeReward(Stake memory _current_stake) internal view returns(uint256) {
        return (_current_stake.amount * apy / 100) * (block.timestamp - _current_stake.since) / (365 days);
    }


    function _addStaker(address staker) internal returns (uint256){

        stakers.push();

        uint256 userIndex = stakers.length - 1;

        stakers[userIndex].user = staker;

        stakes[staker] = userIndex;
        return userIndex;
    }


    function getTotalStaked() external view returns (uint256) {
        return totalStaked;
    }


    function stakeTokens(uint256 _amount) public {

        require(_amount > 0, "amount cannot be 0");


        uint256 index = stakes[msg.sender];

        uint256 timestamp = block.timestamp;

        uint256 reward = 0;

        if (index == 0){



            index = _addStaker(msg.sender);
        } else {
            reward = calculateStakeReward(stakers[index].address_stake);
        }

        uint256 newStake = stakers[index].address_stake.amount + _amount + reward;



        stakers[index].address_stake = Stake(msg.sender, newStake, timestamp);
        totalStaked += newStake;


        aniaToken.transferFrom(msg.sender, address(this), _amount);
    }


    function unstakeTokens(uint256 _amount) public {

        uint256 index = stakes[msg.sender];


        uint256 userStakes = stakers[index].address_stake.amount;


        require(userStakes > 0, "amount has to be more than 0");


        uint256 reward = calculateStakeReward(stakers[index].address_stake);


        uint256 stakedWithRewards = userStakes + reward;
        require(_amount <= stakedWithRewards, "amount has to be less or equal than current stakes with rewards");
        aniaToken.transfer(msg.sender, _amount);


        stakers[index].address_stake = Stake(msg.sender, userStakes + reward - _amount, block.timestamp);


        if (userStakes < _amount) {
            totalStaked -= userStakes;  
        } else {
            totalStaked -= _amount;
        }
    }


    function hasRewards() public view returns(uint256) {

        uint256 index = stakes[msg.sender];
        return calculateStakeReward(stakers[index].address_stake);
    }


    function hasStakeWithRewards(address _address) public view returns(uint256) {

        uint256 index = stakes[_address];

        if (stakers[index].user != _address) {
            return 0;
        }


        uint256 balance = stakers[index].address_stake.amount;

        if (index != 0) {
            balance += calculateStakeReward(stakers[index].address_stake);
        }
        return balance;
    }


    function redistributeRewards(address[] calldata users) public {

        require(msg.sender == owner, "Only contract creator can redistribute");

        for (uint256 i = 0; i < users.length; i++) {
            uint256 index = stakes[users[i]];
            uint256 reward = calculateStakeReward(stakers[index].address_stake);


            stakers[index].address_stake = Stake(stakers[index].user, stakers[index].address_stake.amount + reward, block.timestamp);


            totalStaked += reward;
        }
    }


    function changeAPY(uint256 _value, address[] calldata users) public {

        require(msg.sender == owner, "Only contract creator can change APY");
        require(
            _value > 0,
            "APY value has to be more than 0, try 100 for (0.100% daily) instead"
        );
        redistributeRewards(users);
        apy = _value;
    }
}

pragma solidity 0.6.12;


import './math/SafeMath.sol';
import './token/BEP20/IBEP20.sol';
import './token/BEP20/SafeBEP20.sol';
import './access/Ownable.sol';


interface IMigratorChef {

    function migrate(IBEP20 token) external returns (IBEP20);
}








contract MasterChef is Ownable {
    using SafeMath for uint256;
    using SafeBEP20 for IBEP20;


    struct UserInfo {
        uint256 amount;     
        uint256 rewardDebt; 











    }


    struct PoolInfo {
        IBEP20 lpToken;           
        uint256 allocPoint;       
        uint256 lastRewardBlock;  
        uint256 accXttPerShare; 
        uint256 executeTimestamp; 
        bool withUpdate;
        bool executed;
    }

    struct PoolAllocPointInfo {
        uint256 pid;       
        uint256 allocPoint;  
        uint256 executeTimestamp; 
        bool withUpdate;
        bool executed;
    }


    IBEP20 public xtt;  


    uint256 public xttPerBlock;

    uint256 public BONUS_MULTIPLIER = 1;

    uint256 public NEW_BONUS_MULTIPLIER = 1;
    uint256 public NEW_BONUS_MULTIPLIER_TIMESTAMP = 0;


    IMigratorChef public migrator;
    IMigratorChef public newMigrator;
    uint256 public newMigratorExecuteTimestamp = 0;



    PoolInfo[] public poolInfo;
    PoolInfo[] public waitingPoolInfo; 
    PoolAllocPointInfo[] public poolAllocPointInfo; 

    mapping (uint256 => mapping (address => UserInfo)) public userInfo;

    uint256 public totalAllocPoint = 0;

    uint256 public startBlock;


    uint256 public constant MIN_TIME_LOCK_PERIOD = 24 hours; 
    uint256 public constant MAX_ARRAY_LENGTH = 100; 


    event Deposit(address indexed user, uint256 indexed pid, uint256 amount);
    event Withdraw(address indexed user, uint256 indexed pid, uint256 amount);
    event EmergencyWithdraw(address indexed user, uint256 indexed pid, uint256 amount);
    event SetMigrator(address indexed user, IMigratorChef migrator);
    event UpdateMultiplier(address indexed user, uint256 multiplierNumber);

    constructor(

        IBEP20 _xtt,



        uint256 _xttPerBlock,
        uint256 _startBlock
    ) public {
        xtt = _xtt;
        xttPerBlock = _xttPerBlock;


        startBlock = _startBlock;


        poolInfo.push(PoolInfo({
            lpToken: _xtt,
            allocPoint: 1000,
            lastRewardBlock: startBlock,
            accXttPerShare: 0,
            executeTimestamp: block.timestamp,
            withUpdate: false,
            executed: true
        }));

        totalAllocPoint = 1000;

    }

    function updateMultiplier(uint256 multiplierNumber, uint256 executeTimestamp) external onlyOwner {

        require(
            executeTimestamp >= block.timestamp.add(MIN_TIME_LOCK_PERIOD),
            "executeTimestamp cannot be sooner than MIN_TIME_LOCK_PERIOD"
        );

        if(NEW_BONUS_MULTIPLIER_TIMESTAMP > 0 && block.timestamp >= NEW_BONUS_MULTIPLIER_TIMESTAMP){
            if(BONUS_MULTIPLIER != NEW_BONUS_MULTIPLIER){
                BONUS_MULTIPLIER = NEW_BONUS_MULTIPLIER;
            }
        }

        NEW_BONUS_MULTIPLIER = multiplierNumber;
        NEW_BONUS_MULTIPLIER_TIMESTAMP = executeTimestamp;

        emit UpdateMultiplier(msg.sender, multiplierNumber);
    }

    function poolLength() external view returns (uint256) {
        return poolInfo.length;
    }



    function add(uint256 _allocPoint, IBEP20 _lpToken, bool _withUpdate, uint256 _executeTimestamp) external onlyOwner {
        require(
            _executeTimestamp >= block.timestamp.add(MIN_TIME_LOCK_PERIOD),
            "_executeTimestamp cannot be sooner than MIN_TIME_LOCK_PERIOD"
        );

        require(
            waitingPoolInfo.length < MAX_ARRAY_LENGTH,
            "Please call executeAddPools function to process adding previous pools before adding more pools"
        );

        waitingPoolInfo.push(PoolInfo({
            lpToken: _lpToken,
            allocPoint: _allocPoint,
            lastRewardBlock: 0,
            accXttPerShare: 0,
            executeTimestamp: _executeTimestamp,
            withUpdate: _withUpdate,
            executed: false
        }));

    }


    function executeAddPools() external onlyOwner {
        uint256 length = waitingPoolInfo.length;
        if(length > 0){
            for (uint256 pid = 0; pid < length; ++pid) {
                PoolInfo storage pool = waitingPoolInfo[pid];
                if(!pool.executed && pool.executeTimestamp <= block.timestamp){

                    if (pool.withUpdate) {
                        massUpdatePools();
                    }
                    uint256 lastRewardBlock = block.number > startBlock ? block.number : startBlock;
                    totalAllocPoint = totalAllocPoint.add(pool.allocPoint);
                    poolInfo.push(PoolInfo({
                        lpToken: pool.lpToken,
                        allocPoint: pool.allocPoint,
                        lastRewardBlock: lastRewardBlock,
                        accXttPerShare: 0,
                        executeTimestamp: pool.executeTimestamp,
                        withUpdate: pool.withUpdate,
                        executed: true
                    }));
                    pool.executed = true;
                    updateStakingPool();


                    removeWaitingPool(pid);
                    pid--;
                    length--;   
                }

            }    
        }

    }

    function removeWaitingPool(uint index)  internal onlyOwner {
        if (index >= waitingPoolInfo.length) return;

        for (uint i = index; i<waitingPoolInfo.length-1; i++){
            waitingPoolInfo[i] = waitingPoolInfo[i+1];
        }
        waitingPoolInfo.pop();

    }




    function set(uint256 _pid, uint256 _allocPoint, bool _withUpdate, uint256 _executeTimestamp) external onlyOwner {
        require(
            _executeTimestamp >= block.timestamp.add(MIN_TIME_LOCK_PERIOD),
            "_executeTimestamp cannot be sooner than MIN_TIME_LOCK_PERIOD"
        );

        require(
            poolAllocPointInfo.length < MAX_ARRAY_LENGTH,
            "Please call executeUpdateAllocPoint function to process previous data before updating more pools"
        );

        poolAllocPointInfo.push(PoolAllocPointInfo({
            pid: _pid,
            allocPoint: _allocPoint,
            executeTimestamp: _executeTimestamp,
            withUpdate: _withUpdate,
            executed: false
        }));
    }


    function executeUpdateAllocPoint() external onlyOwner {

        uint256 length = poolAllocPointInfo.length;
        if(length > 0){
            for (uint256 index = 0; index < length; ++index) {
                PoolAllocPointInfo storage poolAllocPoint = poolAllocPointInfo[index];
                if(!poolAllocPoint.executed && poolAllocPoint.executeTimestamp <= block.timestamp){
                    if (poolAllocPoint.withUpdate) {
                        massUpdatePools();
                    }else{
                        updatePool(poolAllocPoint.pid);
                    }

                    uint256 prevAllocPoint = poolInfo[poolAllocPoint.pid].allocPoint;
                    if (prevAllocPoint != poolAllocPoint.allocPoint) {
                        poolInfo[poolAllocPoint.pid].allocPoint = poolAllocPoint.allocPoint;
                        totalAllocPoint = totalAllocPoint.sub(prevAllocPoint).add(poolAllocPoint.allocPoint);
                        updateStakingPool();
                    }

                    poolAllocPoint.executed = true;




                    removeAllocPoint(index);
                    index--;
                    length--;
                }

            }
        }

    }

    function removeAllocPoint(uint index)  internal onlyOwner {
        if (index >= poolAllocPointInfo.length) return;

        for (uint i = index; i<poolAllocPointInfo.length-1; i++){
            poolAllocPointInfo[i] = poolAllocPointInfo[i+1];
        }
        poolAllocPointInfo.pop();

    }

    function updateStakingPool() internal {
        uint256 length = poolInfo.length;
        uint256 points = 0;
        for (uint256 pid = 1; pid < length; ++pid) {
            points = points.add(poolInfo[pid].allocPoint);
        }
        if (points != 0) {
            points = points.div(3);
            totalAllocPoint = totalAllocPoint.sub(poolInfo[0].allocPoint).add(points);
            poolInfo[0].allocPoint = points;
        }
    }


    function setMigrator(IMigratorChef _migrator, uint256 _executeTimestamp) external onlyOwner {
        require(
            _executeTimestamp >= block.timestamp.add(MIN_TIME_LOCK_PERIOD),
            "_executeTimestamp cannot be sooner than MIN_TIME_LOCK_PERIOD"
        );

        newMigrator = _migrator;
        newMigratorExecuteTimestamp = _executeTimestamp;

        emit SetMigrator(msg.sender, _migrator);
    }


    function executeSetMigrator() external onlyOwner {
        if(newMigratorExecuteTimestamp > 0 && newMigratorExecuteTimestamp <= block.timestamp){
            migrator = newMigrator;
            newMigratorExecuteTimestamp = 0;
            emit SetMigrator(msg.sender, newMigrator);
        }
    }



    function migrate(uint256 _pid) external {
        require(address(migrator) != address(0), "migrate: no migrator");
        PoolInfo storage pool = poolInfo[_pid];
        IBEP20 lpToken = pool.lpToken;
        uint256 bal = lpToken.balanceOf(address(this));
        lpToken.safeApprove(address(migrator), bal);
        IBEP20 newLpToken = migrator.migrate(lpToken);
        require(bal == newLpToken.balanceOf(address(this)), "migrate: bad");
        pool.lpToken = newLpToken;
    }


    function getMultiplier(uint256 _from, uint256 _to) public view returns (uint256) {

        if(NEW_BONUS_MULTIPLIER_TIMESTAMP > 0 && block.timestamp >= NEW_BONUS_MULTIPLIER_TIMESTAMP){
            return _to.sub(_from).mul(NEW_BONUS_MULTIPLIER);
        }

        return _to.sub(_from).mul(BONUS_MULTIPLIER);
    }


    function pendingCake(uint256 _pid, address _user) external view returns (uint256) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_user];
        uint256 accXttPerShare = pool.accXttPerShare;
        uint256 lpSupply = pool.lpToken.balanceOf(address(this));
        if (block.number > pool.lastRewardBlock && lpSupply != 0) {
            uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
            uint256 cakeReward = multiplier.mul(xttPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
            accXttPerShare = accXttPerShare.add(cakeReward.mul(1e12).div(lpSupply));
        }
        return user.amount.mul(accXttPerShare).div(1e12).sub(user.rewardDebt);
    }


    function massUpdatePools() public {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            updatePool(pid);
        }
    }



    function updatePool(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        if (block.number <= pool.lastRewardBlock) {
            return;
        }
        uint256 lpSupply = pool.lpToken.balanceOf(address(this));
        if (lpSupply == 0) {
            pool.lastRewardBlock = block.number;
            return;
        }
        uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
        uint256 xttReward = multiplier.mul(xttPerBlock).mul(pool.allocPoint).div(totalAllocPoint);





        pool.accXttPerShare = pool.accXttPerShare.add(xttReward.mul(1e12).div(lpSupply));
        pool.lastRewardBlock = block.number;
    }


    function deposit(uint256 _pid, uint256 _amount) external {

        require (_pid != 0, 'deposit XTT by staking');

        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        updatePool(_pid);
        if (user.amount > 0) {
            uint256 pending = user.amount.mul(pool.accXttPerShare).div(1e12).sub(user.rewardDebt);
            if(pending > 0) {
                safeXttTransfer(msg.sender, pending);
            }
        }
        if (_amount > 0) {
            pool.lpToken.safeTransferFrom(address(msg.sender), address(this), _amount);
            user.amount = user.amount.add(_amount);
        }
        user.rewardDebt = user.amount.mul(pool.accXttPerShare).div(1e12);
        emit Deposit(msg.sender, _pid, _amount);
    }


    function withdraw(uint256 _pid, uint256 _amount) external {

        require (_pid != 0, 'withdraw XTT by unstaking');

        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        require(user.amount >= _amount, "withdraw: not good");

        updatePool(_pid);
        uint256 pending = user.amount.mul(pool.accXttPerShare).div(1e12).sub(user.rewardDebt);
        if(pending > 0) {
            safeXttTransfer(msg.sender, pending);
        }
        if(_amount > 0) {
            user.amount = user.amount.sub(_amount);
            pool.lpToken.safeTransfer(address(msg.sender), _amount);
        }
        user.rewardDebt = user.amount.mul(pool.accXttPerShare).div(1e12);
        emit Withdraw(msg.sender, _pid, _amount);
    }


    function enterStaking(uint256 _amount) external {
        PoolInfo storage pool = poolInfo[0];
        UserInfo storage user = userInfo[0][msg.sender];
        updatePool(0);
        if (user.amount > 0) {
            uint256 pending = user.amount.mul(pool.accXttPerShare).div(1e12).sub(user.rewardDebt);
            if(pending > 0) {
                safeXttTransfer(msg.sender, pending);
            }
        }
        if(_amount > 0) {
            pool.lpToken.safeTransferFrom(address(msg.sender), address(this), _amount);
            user.amount = user.amount.add(_amount);
        }
        user.rewardDebt = user.amount.mul(pool.accXttPerShare).div(1e12);




        emit Deposit(msg.sender, 0, _amount);
    }


    function leaveStaking(uint256 _amount) external {
        PoolInfo storage pool = poolInfo[0];
        UserInfo storage user = userInfo[0][msg.sender];
        require(user.amount >= _amount, "withdraw: not good");
        updatePool(0);
        uint256 pending = user.amount.mul(pool.accXttPerShare).div(1e12).sub(user.rewardDebt);
        if(pending > 0) {
            safeXttTransfer(msg.sender, pending);
        }
        if(_amount > 0) {
            user.amount = user.amount.sub(_amount);
            pool.lpToken.safeTransfer(address(msg.sender), _amount);
        }
        user.rewardDebt = user.amount.mul(pool.accXttPerShare).div(1e12);



        emit Withdraw(msg.sender, 0, _amount);
    }


    function emergencyWithdraw(uint256 _pid) external {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        pool.lpToken.safeTransfer(address(msg.sender), user.amount);
        emit EmergencyWithdraw(msg.sender, _pid, user.amount);
        user.amount = 0;
        user.rewardDebt = 0;
    }


    function safeXttTransfer(address _to, uint256 _amount) internal {
        xtt.safeTransfer(_to, _amount);
    }
}

pragma solidity 0.6.12;


import './math/SafeMath.sol';
import './token/BEP20/IBEP20.sol';
import './token/BEP20/SafeBEP20.sol';
import './access/Ownable.sol';


interface IMigratorChef {

    function migrate(IBEP20 token) external returns (IBEP20);
}








contract MasterChef is Ownable {
    using SafeMath for uint256;
    using SafeBEP20 for IBEP20;


    struct UserInfo {
        uint256 amount;     
        uint256 rewardDebt; 











    }


    struct PoolInfo {
        IBEP20 lpToken;           
        uint256 allocPoint;       
        uint256 lastRewardBlock;  
        uint256 accXttPerShare; 
        uint256 executeTimestamp; 
        bool withUpdate;
        bool executed;
    }

    struct PoolAllocPointInfo {
        uint256 pid;       
        uint256 allocPoint;  
        uint256 executeTimestamp; 
        bool withUpdate;
        bool executed;
    }


    IBEP20 public xtt;  


    uint256 public xttPerBlock;

    uint256 public BONUS_MULTIPLIER = 1;

    uint256 public NEW_BONUS_MULTIPLIER = 1;
    uint256 public NEW_BONUS_MULTIPLIER_TIMESTAMP = 0;


    IMigratorChef public migrator;
    IMigratorChef public newMigrator;
    uint256 public newMigratorExecuteTimestamp = 0;



    PoolInfo[] public poolInfo;
    PoolInfo[] public waitingPoolInfo; 
    PoolAllocPointInfo[] public poolAllocPointInfo; 

    mapping (uint256 => mapping (address => UserInfo)) public userInfo;

    uint256 public totalAllocPoint = 0;

    uint256 public startBlock;


    uint256 public constant MIN_TIME_LOCK_PERIOD = 24 hours; 
    uint256 public constant MAX_ARRAY_LENGTH = 100; 


    event Deposit(address indexed user, uint256 indexed pid, uint256 amount);
    event Withdraw(address indexed user, uint256 indexed pid, uint256 amount);
    event EmergencyWithdraw(address indexed user, uint256 indexed pid, uint256 amount);
    event SetMigrator(address indexed user, IMigratorChef migrator);
    event UpdateMultiplier(address indexed user, uint256 multiplierNumber);

    constructor(

        IBEP20 _xtt,



        uint256 _xttPerBlock,
        uint256 _startBlock
    ) public {
        xtt = _xtt;
        xttPerBlock = _xttPerBlock;


        startBlock = _startBlock;


        poolInfo.push(PoolInfo({
            lpToken: _xtt,
            allocPoint: 1000,
            lastRewardBlock: startBlock,
            accXttPerShare: 0,
            executeTimestamp: block.timestamp,
            withUpdate: false,
            executed: true
        }));

        totalAllocPoint = 1000;

    }

    function updateMultiplier(uint256 multiplierNumber, uint256 executeTimestamp) external onlyOwner {

        require(
            executeTimestamp >= block.timestamp.add(MIN_TIME_LOCK_PERIOD),
            "executeTimestamp cannot be sooner than MIN_TIME_LOCK_PERIOD"
        );

        if(NEW_BONUS_MULTIPLIER_TIMESTAMP > 0 && block.timestamp >= NEW_BONUS_MULTIPLIER_TIMESTAMP){
            if(BONUS_MULTIPLIER != NEW_BONUS_MULTIPLIER){
                BONUS_MULTIPLIER = NEW_BONUS_MULTIPLIER;
            }
        }

        NEW_BONUS_MULTIPLIER = multiplierNumber;
        NEW_BONUS_MULTIPLIER_TIMESTAMP = executeTimestamp;

        emit UpdateMultiplier(msg.sender, multiplierNumber);
    }

    function poolLength() external view returns (uint256) {
        return poolInfo.length;
    }



    function add(uint256 _allocPoint, IBEP20 _lpToken, bool _withUpdate, uint256 _executeTimestamp) external onlyOwner {
        require(
            _executeTimestamp >= block.timestamp.add(MIN_TIME_LOCK_PERIOD),
            "_executeTimestamp cannot be sooner than MIN_TIME_LOCK_PERIOD"
        );

        require(
            waitingPoolInfo.length < MAX_ARRAY_LENGTH,
            "Please call executeAddPools function to process adding previous pools before adding more pools"
        );

        waitingPoolInfo.push(PoolInfo({
            lpToken: _lpToken,
            allocPoint: _allocPoint,
            lastRewardBlock: 0,
            accXttPerShare: 0,
            executeTimestamp: _executeTimestamp,
            withUpdate: _withUpdate,
            executed: false
        }));

    }


    function executeAddPools() external onlyOwner {
        uint256 length = waitingPoolInfo.length;
        if(length > 0){
            for (uint256 pid = 0; pid < length; ++pid) {
                PoolInfo storage pool = waitingPoolInfo[pid];
                if(!pool.executed && pool.executeTimestamp <= block.timestamp){

                    if (pool.withUpdate) {
                        massUpdatePools();
                    }
                    uint256 lastRewardBlock = block.number > startBlock ? block.number : startBlock;
                    totalAllocPoint = totalAllocPoint.add(pool.allocPoint);
                    poolInfo.push(PoolInfo({
                        lpToken: pool.lpToken,
                        allocPoint: pool.allocPoint,
                        lastRewardBlock: lastRewardBlock,
                        accXttPerShare: 0,
                        executeTimestamp: pool.executeTimestamp,
                        withUpdate: pool.withUpdate,
                        executed: true
                    }));
                    pool.executed = true;
                    updateStakingPool();


                    removeWaitingPool(pid);
                    pid--;
                    length--;   
                }

            }    
        }

    }

    function removeWaitingPool(uint index)  internal onlyOwner {
        if (index >= waitingPoolInfo.length) return;

        for (uint i = index; i<waitingPoolInfo.length-1; i++){
            waitingPoolInfo[i] = waitingPoolInfo[i+1];
        }
        waitingPoolInfo.pop();

    }




    function set(uint256 _pid, uint256 _allocPoint, bool _withUpdate, uint256 _executeTimestamp) external onlyOwner {
        require(
            _executeTimestamp >= block.timestamp.add(MIN_TIME_LOCK_PERIOD),
            "_executeTimestamp cannot be sooner than MIN_TIME_LOCK_PERIOD"
        );

        require(
            poolAllocPointInfo.length < MAX_ARRAY_LENGTH,
            "Please call executeUpdateAllocPoint function to process previous data before updating more pools"
        );

        poolAllocPointInfo.push(PoolAllocPointInfo({
            pid: _pid,
            allocPoint: _allocPoint,
            executeTimestamp: _executeTimestamp,
            withUpdate: _withUpdate,
            executed: false
        }));
    }


    function executeUpdateAllocPoint() external onlyOwner {

        uint256 length = poolAllocPointInfo.length;
        if(length > 0){
            for (uint256 index = 0; index < length; ++index) {
                PoolAllocPointInfo storage poolAllocPoint = poolAllocPointInfo[index];
                if(!poolAllocPoint.executed && poolAllocPoint.executeTimestamp <= block.timestamp){
                    if (poolAllocPoint.withUpdate) {
                        massUpdatePools();
                    }else{
                        updatePool(poolAllocPoint.pid);
                    }

                    uint256 prevAllocPoint = poolInfo[poolAllocPoint.pid].allocPoint;
                    if (prevAllocPoint != poolAllocPoint.allocPoint) {
                        poolInfo[poolAllocPoint.pid].allocPoint = poolAllocPoint.allocPoint;
                        totalAllocPoint = totalAllocPoint.sub(prevAllocPoint).add(poolAllocPoint.allocPoint);
                        updateStakingPool();
                    }

                    poolAllocPoint.executed = true;




                    removeAllocPoint(index);
                    index--;
                    length--;
                }

            }
        }

    }

    function removeAllocPoint(uint index)  internal onlyOwner {
        if (index >= poolAllocPointInfo.length) return;

        for (uint i = index; i<poolAllocPointInfo.length-1; i++){
            poolAllocPointInfo[i] = poolAllocPointInfo[i+1];
        }
        poolAllocPointInfo.pop();

    }

    function updateStakingPool() internal {
        uint256 length = poolInfo.length;
        uint256 points = 0;
        for (uint256 pid = 1; pid < length; ++pid) {
            points = points.add(poolInfo[pid].allocPoint);
        }
        if (points != 0) {
            points = points.div(3);
            totalAllocPoint = totalAllocPoint.sub(poolInfo[0].allocPoint).add(points);
            poolInfo[0].allocPoint = points;
        }
    }


    function setMigrator(IMigratorChef _migrator, uint256 _executeTimestamp) external onlyOwner {
        require(
            _executeTimestamp >= block.timestamp.add(MIN_TIME_LOCK_PERIOD),
            "_executeTimestamp cannot be sooner than MIN_TIME_LOCK_PERIOD"
        );

        newMigrator = _migrator;
        newMigratorExecuteTimestamp = _executeTimestamp;

        emit SetMigrator(msg.sender, _migrator);
    }


    function executeSetMigrator() external onlyOwner {
        if(newMigratorExecuteTimestamp > 0 && newMigratorExecuteTimestamp <= block.timestamp){
            migrator = newMigrator;
            newMigratorExecuteTimestamp = 0;
            emit SetMigrator(msg.sender, newMigrator);
        }
    }



    function migrate(uint256 _pid) external {
        require(address(migrator) != address(0), "migrate: no migrator");
        PoolInfo storage pool = poolInfo[_pid];
        IBEP20 lpToken = pool.lpToken;
        uint256 bal = lpToken.balanceOf(address(this));
        lpToken.safeApprove(address(migrator), bal);
        IBEP20 newLpToken = migrator.migrate(lpToken);
        require(bal == newLpToken.balanceOf(address(this)), "migrate: bad");
        pool.lpToken = newLpToken;
    }


    function getMultiplier(uint256 _from, uint256 _to) public view returns (uint256) {

        if(NEW_BONUS_MULTIPLIER_TIMESTAMP > 0 && block.timestamp >= NEW_BONUS_MULTIPLIER_TIMESTAMP){
            return _to.sub(_from).mul(NEW_BONUS_MULTIPLIER);
        }

        return _to.sub(_from).mul(BONUS_MULTIPLIER);
    }


    function pendingCake(uint256 _pid, address _user) external view returns (uint256) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_user];
        uint256 accXttPerShare = pool.accXttPerShare;
        uint256 lpSupply = pool.lpToken.balanceOf(address(this));
        if (block.number > pool.lastRewardBlock && lpSupply != 0) {
            uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
            uint256 cakeReward = multiplier.mul(xttPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
            accXttPerShare = accXttPerShare.add(cakeReward.mul(1e12).div(lpSupply));
        }
        return user.amount.mul(accXttPerShare).div(1e12).sub(user.rewardDebt);
    }


    function massUpdatePools() public {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            updatePool(pid);
        }
    }



    function updatePool(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        if (block.number <= pool.lastRewardBlock) {
            return;
        }
        uint256 lpSupply = pool.lpToken.balanceOf(address(this));
        if (lpSupply == 0) {
            pool.lastRewardBlock = block.number;
            return;
        }
        uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
        uint256 xttReward = multiplier.mul(xttPerBlock).mul(pool.allocPoint).div(totalAllocPoint);





        pool.accXttPerShare = pool.accXttPerShare.add(xttReward.mul(1e12).div(lpSupply));
        pool.lastRewardBlock = block.number;
    }


    function deposit(uint256 _pid, uint256 _amount) external {

        require (_pid != 0, 'deposit XTT by staking');

        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        updatePool(_pid);
        if (user.amount > 0) {
            uint256 pending = user.amount.mul(pool.accXttPerShare).div(1e12).sub(user.rewardDebt);
            if(pending > 0) {
                safeXttTransfer(msg.sender, pending);
            }
        }
        if (_amount > 0) {
            pool.lpToken.safeTransferFrom(address(msg.sender), address(this), _amount);
            user.amount = user.amount.add(_amount);
        }
        user.rewardDebt = user.amount.mul(pool.accXttPerShare).div(1e12);
        emit Deposit(msg.sender, _pid, _amount);
    }


    function withdraw(uint256 _pid, uint256 _amount) external {

        require (_pid != 0, 'withdraw XTT by unstaking');

        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        require(user.amount >= _amount, "withdraw: not good");

        updatePool(_pid);
        uint256 pending = user.amount.mul(pool.accXttPerShare).div(1e12).sub(user.rewardDebt);
        if(pending > 0) {
            safeXttTransfer(msg.sender, pending);
        }
        if(_amount > 0) {
            user.amount = user.amount.sub(_amount);
            pool.lpToken.safeTransfer(address(msg.sender), _amount);
        }
        user.rewardDebt = user.amount.mul(pool.accXttPerShare).div(1e12);
        emit Withdraw(msg.sender, _pid, _amount);
    }


    function enterStaking(uint256 _amount) external {
        PoolInfo storage pool = poolInfo[0];
        UserInfo storage user = userInfo[0][msg.sender];
        updatePool(0);
        if (user.amount > 0) {
            uint256 pending = user.amount.mul(pool.accXttPerShare).div(1e12).sub(user.rewardDebt);
            if(pending > 0) {
                safeXttTransfer(msg.sender, pending);
            }
        }
        if(_amount > 0) {
            pool.lpToken.safeTransferFrom(address(msg.sender), address(this), _amount);
            user.amount = user.amount.add(_amount);
        }
        user.rewardDebt = user.amount.mul(pool.accXttPerShare).div(1e12);




        emit Deposit(msg.sender, 0, _amount);
    }


    function leaveStaking(uint256 _amount) external {
        PoolInfo storage pool = poolInfo[0];
        UserInfo storage user = userInfo[0][msg.sender];
        require(user.amount >= _amount, "withdraw: not good");
        updatePool(0);
        uint256 pending = user.amount.mul(pool.accXttPerShare).div(1e12).sub(user.rewardDebt);
        if(pending > 0) {
            safeXttTransfer(msg.sender, pending);
        }
        if(_amount > 0) {
            user.amount = user.amount.sub(_amount);
            pool.lpToken.safeTransfer(address(msg.sender), _amount);
        }
        user.rewardDebt = user.amount.mul(pool.accXttPerShare).div(1e12);



        emit Withdraw(msg.sender, 0, _amount);
    }


    function emergencyWithdraw(uint256 _pid) external {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        pool.lpToken.safeTransfer(address(msg.sender), user.amount);
        emit EmergencyWithdraw(msg.sender, _pid, user.amount);
        user.amount = 0;
        user.rewardDebt = 0;
    }


    function safeXttTransfer(address _to, uint256 _amount) internal {
        xtt.safeTransfer(_to, _amount);
    }
}

pragma solidity >=0.8.0;



library SafeMath {
  function mul(uint256 a, uint256 b) internal pure returns (uint256) {
    uint256 c = a * b;
    assert(a == 0 || c / a == b);
    return c;
  }

  function div(uint256 a, uint256 b) internal pure returns (uint256) {

    uint256 c = a / b;

    return c;
  }

  function sub(uint256 a, uint256 b) internal pure returns (uint256) {
    assert(b <= a);
    return a - b;
  }

  function add(uint256 a, uint256 b) internal pure returns (uint256) {
    uint256 c = a + b;
    assert(c >= a);
    return c;
  }
}

library EnumerableSet {









    struct Set {

        bytes32[] _values;



        mapping (bytes32 => uint256) _indexes;
    }


    function _add(Set storage set, bytes32 value) private returns (bool) {
        if (!_contains(set, value)) {
            set._values.push(value);


            set._indexes[value] = set._values.length;
            return true;
        } else {
            return false;
        }
    }


    function _remove(Set storage set, bytes32 value) private returns (bool) {

        uint256 valueIndex = set._indexes[value];

        if (valueIndex != 0) { 




            uint256 toDeleteIndex = valueIndex - 1;
            uint256 lastIndex = set._values.length - 1;




            bytes32 lastvalue = set._values[lastIndex];


            set._values[toDeleteIndex] = lastvalue;

            set._indexes[lastvalue] = toDeleteIndex + 1; 


            set._values.pop();


            delete set._indexes[value];

            return true;
        } else {
            return false;
        }
    }


    function _contains(Set storage set, bytes32 value) private view returns (bool) {
        return set._indexes[value] != 0;
    }


    function _length(Set storage set) private view returns (uint256) {
        return set._values.length;
    }


    function _at(Set storage set, uint256 index) private view returns (bytes32) {
        require(set._values.length > index, "EnumerableSet: index out of bounds");
        return set._values[index];
    }



    struct AddressSet {
        Set _inner;
    }


    function add(AddressSet storage set, address value) internal returns (bool) {
        return _add(set._inner, bytes32(uint(uint160(value))));
    }


    function remove(AddressSet storage set, address value) internal returns (bool) {
        return _remove(set._inner, bytes32(uint(uint160(value))));
    }


    function contains(AddressSet storage set, address value) internal view returns (bool) {
        return _contains(set._inner, bytes32(uint(uint160(value))));
    }


    function length(AddressSet storage set) internal view returns (uint256) {
        return _length(set._inner);
    }


    function at(AddressSet storage set, uint256 index) internal view returns (address) {
        return address(uint160(uint(_at(set._inner, index))));
    }




    struct UintSet {
        Set _inner;
    }


    function add(UintSet storage set, uint256 value) internal returns (bool) {
        return _add(set._inner, bytes32(value));
    }


    function remove(UintSet storage set, uint256 value) internal returns (bool) {
        return _remove(set._inner, bytes32(value));
    }


    function contains(UintSet storage set, uint256 value) internal view returns (bool) {
        return _contains(set._inner, bytes32(value));
    }


    function length(UintSet storage set) internal view returns (uint256) {
        return _length(set._inner);
    }


    function at(UintSet storage set, uint256 index) internal view returns (uint256) {
        return uint256(_at(set._inner, index));
    }
}


contract Ownable {
  address public owner;


  event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);



  constructor()  {
    owner = msg.sender;
  }



  modifier onlyOwner() {
    require(msg.sender == owner);
    _;
  }



  function transferOwnership(address newOwner) onlyOwner public {
    require(newOwner != address(0));
    emit OwnershipTransferred(owner, newOwner);
    owner = newOwner;
  }
}


interface Token {
    function transferFrom(address, address, uint) external returns (bool);
    function transfer(address, uint) external returns (bool);
}

contract BSB_StakingSmartStakers is Ownable {
    using SafeMath for uint;
    using EnumerableSet for EnumerableSet.AddressSet;

    event RewardsTransferred(address holder, uint amount);
    event RewardsRestaked(address holder, uint amount);


    address public constant tokenDepositAddress = 0xA478A13242b64629bff309125770B69f75Bd77cb;


    uint public rewardRate = 52000;
    uint public constant rewardInterval = 365 days;


    uint public constant stakingFeeRate = 100;


    uint public constant unstakingFeeRate = 50;


    uint public constant unstakeTime = 90 days;


    uint public constant claimTime = 10 days;


    uint public constant maxPoolSize = 50000000000000000000000;
    uint public availablePoolSize = 50000000000000000000000;


    uint public constant totalRewards = 200000000000000000000000; 

    uint public totalClaimedRewards = 0;
    uint public totalDeposited = 0; 
    bool public ended ;

    EnumerableSet.AddressSet private holders;

    mapping (address => uint) public depositedTokens;
    mapping (address => uint) public maxDepositedTokens;
    mapping (address => uint) public stakingTime; 
    mapping (address => uint) public firstTime; 
    mapping (address => uint) public lastClaimedTime; 
    mapping (address => uint) public progressiveTime; 
    mapping (address => uint) public totalEarnedTokens;

    mapping (address => uint) public rewardEnded;


    mapping (address => uint) public alreadyProgUnstaked; 
    mapping (address => uint) public amountPerInterval;
    uint public number_intervals = 4;
    uint public duration_interval = 30 days;


    uint extraAPY = 10400; 


    uint percent_claim = 2; 
    mapping (address => uint) public unclaimed;

    uint public endTime;




    function end() public onlyOwner returns (bool){
        require(!ended, "Staking already ended");
        address _aux;

        for(uint i = 0; i < holders.length(); i = i.add(1)){
            _aux = holders.at(i);
            rewardEnded[_aux] = getPendingRewards(_aux);
            unclaimed[_aux] = 0;
            stakingTime[_aux] = block.timestamp;
            progressiveTime[_aux] = block.timestamp;
            alreadyProgUnstaked[_aux] = 0;
            amountPerInterval[_aux] = depositedTokens[_aux].div(number_intervals);
        }

        ended = true;
        endTime = block.timestamp;
        return true;
    }

    function getRewardsLeft() public view returns (uint){

        uint _res;
        if(ended){
            _res = 0;
        }else{
            uint totalPending;

            for(uint i = 0; i < holders.length(); i = i.add(1)){
                totalPending = totalPending.add(getPendingRewards(holders.at(i)));
            }
            if(totalRewards > totalClaimedRewards.add(totalPending)){
                _res = totalRewards.sub(totalClaimedRewards).sub(totalPending);
            }else{
                _res = 0;
            }

        }

        return _res;
    }

    function updateAccount(address account, bool _restake, bool _withdraw) private returns (bool){
        uint pendingDivs = getPendingRewards(account);
        uint toSend = pendingDivs;

        if(depositedTokens[account].mul(percent_claim).div(100) < pendingDivs){
            toSend = depositedTokens[account].mul(percent_claim).div(100);
        }

        if (pendingDivs > 0) {
            if(ended){ 
                if(!_withdraw){

                    if(depositedTokens[account] == 0){

                        if( maxDepositedTokens[account].mul(percent_claim).div(100) > pendingDivs ){
                            toSend = pendingDivs;
                        }else{
                            toSend = maxDepositedTokens[account].mul(percent_claim).div(100);
                        }
                    }
                     rewardEnded[account] = rewardEnded[account].sub(toSend);
                     require(Token(tokenDepositAddress).transfer(account, toSend), "Could not transfer tokens.");
                     totalEarnedTokens[account] = totalEarnedTokens[account].add(toSend);
                     totalClaimedRewards = totalClaimedRewards.add(toSend);
                }

            }else{

                if(_restake){ 
                    require(pendingDivs <= availablePoolSize, "No spot available");
                    depositedTokens[account] = depositedTokens[account].add(pendingDivs);

                    unclaimed[account] = 0;

                    if(depositedTokens[account] > maxDepositedTokens[account]){
                        maxDepositedTokens[account] = depositedTokens[account];
                    } 
                    availablePoolSize = availablePoolSize.sub(pendingDivs);
                    totalDeposited = totalDeposited.add(pendingDivs);
                    totalEarnedTokens[account] = totalEarnedTokens[account].add(pendingDivs);
                    totalClaimedRewards = totalClaimedRewards.add(pendingDivs);
                }else if(_withdraw){ 
                    unclaimed[account] = pendingDivs;

                }else{ 
                    if(depositedTokens[account] == 0){

                        if( maxDepositedTokens[account].mul(percent_claim).div(100) > pendingDivs ){
                            toSend = pendingDivs;
                        }else{
                            toSend = maxDepositedTokens[account].mul(percent_claim).div(100);
                        }
                    }
                    uint toUnclaimed = 0;
                    uint subUnclaimed = 0;
                    uint pendingWithoutUnclaimed = getOnlyPendingRewards(account);
                    if(toSend > pendingWithoutUnclaimed){
                        subUnclaimed = toSend.sub(pendingWithoutUnclaimed);
                        toUnclaimed = 0;
                    }else{
                        toUnclaimed = pendingWithoutUnclaimed.sub(toSend);
                        subUnclaimed = 0;
                    }

                    unclaimed[account] = unclaimed[account].add(toUnclaimed).sub(subUnclaimed);
                    require(Token(tokenDepositAddress).transfer(account, toSend), "Could not transfer tokens.");
                    totalEarnedTokens[account] = totalEarnedTokens[account].add(toSend);
                    totalClaimedRewards = totalClaimedRewards.add(toSend);
                }
            }    
        }
        lastClaimedTime[account] = block.timestamp;
        return true;
    }

    function getAPY(address _staker) public view returns(uint){
        uint apy = rewardRate;
        if(block.timestamp.sub(firstTime[_staker]) > unstakeTime && alreadyProgUnstaked[_staker] == 0 && !ended){
            apy = apy.add(extraAPY);
        }
        return apy;
    }

    function getPendingRewards(address _holder) public view returns (uint) { 
        if (!holders.contains(_holder)) return 0;
        if (depositedTokens[_holder] == 0 && unclaimed[_holder] == 0 && !ended) return 0;
        uint pendingDivs;
        if(!ended){
             uint timeDiff = block.timestamp.sub(lastClaimedTime[_holder]);
             uint stakedAmount = depositedTokens[_holder];


             uint apy = getAPY(_holder);

             pendingDivs = stakedAmount
                                .mul(apy) 
                                .mul(timeDiff)
                                .div(rewardInterval)
                                .div(1e4);

             pendingDivs = pendingDivs.add(unclaimed[_holder]);

        }else{
            pendingDivs = rewardEnded[_holder];
        }

        return pendingDivs;
    }

    function getOnlyPendingRewards(address _holder) internal view returns (uint) { 
        if (!holders.contains(_holder)) return 0;
        if (depositedTokens[_holder] == 0 || ended) return 0;
        uint pendingDivs;
        if(!ended){
             uint timeDiff = block.timestamp.sub(lastClaimedTime[_holder]);
             uint stakedAmount = depositedTokens[_holder];


             uint apy = getAPY(_holder);

             pendingDivs = stakedAmount
                                .mul(apy) 
                                .mul(timeDiff)
                                .div(rewardInterval)
                                .div(1e4);

        }else{
            pendingDivs = 0;
        }

        return pendingDivs;
    }

    function getNumberOfHolders() public view returns (uint) {
        return holders.length();
    }

    function deposit(uint amountToStake) public returns (bool){
        require(!ended, "Staking has ended");
        require(getRewardsLeft() > 0, "No rewards left");
        require(amountToStake > 0, "Cannot deposit 0 Tokens");

        require(Token(tokenDepositAddress).transferFrom(msg.sender, address(this), amountToStake), "Insufficient Token Allowance");


        require(updateAccount(msg.sender, true, false), "Error updating account");

        uint fee = amountToStake.mul(stakingFeeRate).div(1e4);
        uint amountAfterFee = amountToStake.sub(fee);
        require(amountAfterFee <= availablePoolSize, "No space available");
        require(Token(tokenDepositAddress).transfer(owner, fee), "Could not transfer deposit fee.");

        depositedTokens[msg.sender] = depositedTokens[msg.sender].add(amountAfterFee);
        if(depositedTokens[msg.sender] > maxDepositedTokens[msg.sender]){
            maxDepositedTokens[msg.sender] = depositedTokens[msg.sender];
        } 
        availablePoolSize = availablePoolSize.sub(amountAfterFee);
        totalDeposited = totalDeposited.add(amountAfterFee);

        if (!holders.contains(msg.sender)) {
            holders.add(msg.sender);
            firstTime[msg.sender] = block.timestamp;

        }


        amountPerInterval[msg.sender] = 0;
        if(alreadyProgUnstaked[msg.sender] > 0){
            firstTime[msg.sender] = block.timestamp;
        } 

        alreadyProgUnstaked[msg.sender] = 0;

        stakingTime[msg.sender] = block.timestamp;
        return true;
    }


    function getMaxAmountWithdrawable(address _staker) public view returns(uint){
        uint _res = 0;
        if(block.timestamp.sub(stakingTime[msg.sender]) < unstakeTime && !ended && alreadyProgUnstaked[_staker] == 0){
            _res = 0;
        }else if(alreadyProgUnstaked[_staker] == 0 && !ended){

            if(block.timestamp.sub(stakingTime[msg.sender]) > unstakeTime){
                _res = depositedTokens[_staker].div(number_intervals);
            }

        }else{
            uint _time = progressiveTime[_staker];

            if(block.timestamp < _time.add(duration_interval)){
                _res = 0;
            }else{


                uint _numIntervals = (block.timestamp.sub(_time)).div(duration_interval);

                if(_numIntervals == 0){
                    return 0;
                }
                if(!ended){
                    _numIntervals = _numIntervals.add(1);
                }


                if(_numIntervals > number_intervals){
                    _numIntervals = number_intervals;
                }

                if(_numIntervals.mul(amountPerInterval[_staker]) > alreadyProgUnstaked[_staker]){
                    _res = _numIntervals.mul(amountPerInterval[_staker]).sub(alreadyProgUnstaked[_staker]);
                }else{
                    _res = 0;
                }
            }


        }

        return _res;
    }


    function withdraw2(uint amountToWithdraw) public returns (bool){
        require(holders.contains(msg.sender), "Not a staker");
        require(amountToWithdraw <= getMaxAmountWithdrawable(msg.sender), "Maximum reached");
        require(alreadyProgUnstaked[msg.sender] > 0 || ended, "Use withdraw first");

        alreadyProgUnstaked[msg.sender] = alreadyProgUnstaked[msg.sender].add(amountToWithdraw);

        uint fee = amountToWithdraw.mul(unstakingFeeRate).div(1e4);
        uint amountAfterFee = amountToWithdraw.sub(fee);

        updateAccount(msg.sender, false, true);

        require(Token(tokenDepositAddress).transfer(owner, fee), "Could not transfer withdraw fee.");
        require(Token(tokenDepositAddress).transfer(msg.sender, amountAfterFee), "Could not transfer tokens.");

        depositedTokens[msg.sender] = depositedTokens[msg.sender].sub(amountToWithdraw);
        availablePoolSize = availablePoolSize.add(amountToWithdraw);
        totalDeposited = totalDeposited.sub(amountToWithdraw);

        if (holders.contains(msg.sender) && depositedTokens[msg.sender] == 0 && getPendingRewards(msg.sender) == 0) {
            holders.remove(msg.sender);
            firstTime[msg.sender] = 0;
        }
        return true;
    }


    function withdraw(uint amountToWithdraw) public returns (bool){
        require(holders.contains(msg.sender), "Not a staker");
        require(alreadyProgUnstaked[msg.sender] == 0 && !ended , "Use withdraw2 function");
        amountPerInterval[msg.sender] = depositedTokens[msg.sender].div(number_intervals);
        require(depositedTokens[msg.sender].div(number_intervals) >= amountToWithdraw, "Invalid amount to withdraw");
        alreadyProgUnstaked[msg.sender] = amountToWithdraw;
        require(block.timestamp.sub(stakingTime[msg.sender]) > unstakeTime || ended, "You recently staked, please wait before withdrawing.");



        updateAccount(msg.sender, false, true);

        uint fee = amountToWithdraw.mul(unstakingFeeRate).div(1e4);
        uint amountAfterFee = amountToWithdraw.sub(fee);

        require(Token(tokenDepositAddress).transfer(owner, fee), "Could not transfer withdraw fee.");
        require(Token(tokenDepositAddress).transfer(msg.sender, amountAfterFee), "Could not transfer tokens.");

        depositedTokens[msg.sender] = depositedTokens[msg.sender].sub(amountToWithdraw);
        availablePoolSize = availablePoolSize.add(amountToWithdraw);
        totalDeposited = totalDeposited.sub(amountToWithdraw);

        progressiveTime[msg.sender] = block.timestamp;

        return true;
    }

    function getTimeToWithdraw(address _staker) public view returns (uint){
        if(getMaxAmountWithdrawable(_staker) != 0) return 0;

        uint _res = 0;
        uint _time = stakingTime[_staker];
        if(alreadyProgUnstaked[_staker] == 0 && !ended ){

            if(block.timestamp <= _time.add(unstakeTime)){
                _res = _time.add(unstakeTime).sub(block.timestamp);
            }

        }else{
            _time = progressiveTime[_staker];

            for(uint i = 1; i <= number_intervals; i = i.add(1)){
                if(block.timestamp < _time.add(duration_interval.mul(i))){
                    _res = _time.add(duration_interval.mul(i)).sub(block.timestamp);
                    break;
                }
            }

        }
        return _res;
    }

    function getTimeToClaim(address _staker) public view returns (uint){
        uint _res = 0;

        if(lastClaimedTime[_staker].add(claimTime) > block.timestamp){
            _res = lastClaimedTime[_staker].add(claimTime).sub(block.timestamp);
        }

        return _res;
    }

    function claimDivs() public  returns (bool){
        require(holders.contains(msg.sender), "Not a staker");
        require(block.timestamp.sub(lastClaimedTime[msg.sender]) > claimTime, "Not yet");
        updateAccount(msg.sender, false, false);
        return true;
    }

    function getStakersList(uint startIndex, uint endIndex) public view returns (address[] memory stakers, uint[] memory stakingTimestamps,  uint[] memory lastClaimedTimeStamps, uint[] memory stakedTokens) {
        require (startIndex < endIndex);

        uint length = endIndex.sub(startIndex);
        address[] memory _stakers = new address[](length);
        uint[] memory _stakingTimestamps = new uint[](length);
        uint[] memory _lastClaimedTimeStamps = new uint[](length);
        uint[] memory _stakedTokens = new uint[](length);

        for (uint i = startIndex; i < endIndex; i = i.add(1)) {
            address staker = holders.at(i);
            uint listIndex = i.sub(startIndex);
            _stakers[listIndex] = staker;
            _stakingTimestamps[listIndex] = stakingTime[staker];
            _lastClaimedTimeStamps[listIndex] = lastClaimedTime[staker];
            _stakedTokens[listIndex] = depositedTokens[staker];
        }

        return (_stakers, _stakingTimestamps, _lastClaimedTimeStamps, _stakedTokens);
    }


    function transferAnyERC20Tokens(address _tokenAddr, address _to, uint _amount) public onlyOwner  returns (bool){
        require (_tokenAddr != tokenDepositAddress, "Cannot Transfer Out this token");
        Token(_tokenAddr).transfer(_to, _amount);
        return true;
    }

    function getClaimableAmount(address account) public view returns (uint){
        uint pendingDivs = getPendingRewards(account);
        uint toSend = pendingDivs;

        if(depositedTokens[account].mul(percent_claim).div(100) < pendingDivs){
            toSend = depositedTokens[account].mul(percent_claim).div(100);
        }

        if (pendingDivs > 0) {
            if(ended){ 
                    if(depositedTokens[account] == 0){

                        if( maxDepositedTokens[account].mul(percent_claim).div(100) > pendingDivs ){
                            toSend = pendingDivs;
                        }else{
                            toSend = maxDepositedTokens[account].mul(percent_claim).div(100);
                        }
                    }

            }else{
                if(depositedTokens[account] == 0){

                    if( maxDepositedTokens[account].mul(percent_claim).div(100) > pendingDivs ){
                        toSend = pendingDivs;
                    }else{
                        toSend = maxDepositedTokens[account].mul(percent_claim).div(100);
                    }
                }
            }    
        }
        return toSend;
    }

}

pragma solidity >=0.8.0;



library SafeMath {
  function mul(uint256 a, uint256 b) internal pure returns (uint256) {
    uint256 c = a * b;
    assert(a == 0 || c / a == b);
    return c;
  }

  function div(uint256 a, uint256 b) internal pure returns (uint256) {

    uint256 c = a / b;

    return c;
  }

  function sub(uint256 a, uint256 b) internal pure returns (uint256) {
    assert(b <= a);
    return a - b;
  }

  function add(uint256 a, uint256 b) internal pure returns (uint256) {
    uint256 c = a + b;
    assert(c >= a);
    return c;
  }
}

library EnumerableSet {









    struct Set {

        bytes32[] _values;



        mapping (bytes32 => uint256) _indexes;
    }


    function _add(Set storage set, bytes32 value) private returns (bool) {
        if (!_contains(set, value)) {
            set._values.push(value);


            set._indexes[value] = set._values.length;
            return true;
        } else {
            return false;
        }
    }


    function _remove(Set storage set, bytes32 value) private returns (bool) {

        uint256 valueIndex = set._indexes[value];

        if (valueIndex != 0) { 




            uint256 toDeleteIndex = valueIndex - 1;
            uint256 lastIndex = set._values.length - 1;




            bytes32 lastvalue = set._values[lastIndex];


            set._values[toDeleteIndex] = lastvalue;

            set._indexes[lastvalue] = toDeleteIndex + 1; 


            set._values.pop();


            delete set._indexes[value];

            return true;
        } else {
            return false;
        }
    }


    function _contains(Set storage set, bytes32 value) private view returns (bool) {
        return set._indexes[value] != 0;
    }


    function _length(Set storage set) private view returns (uint256) {
        return set._values.length;
    }


    function _at(Set storage set, uint256 index) private view returns (bytes32) {
        require(set._values.length > index, "EnumerableSet: index out of bounds");
        return set._values[index];
    }



    struct AddressSet {
        Set _inner;
    }


    function add(AddressSet storage set, address value) internal returns (bool) {
        return _add(set._inner, bytes32(uint(uint160(value))));
    }


    function remove(AddressSet storage set, address value) internal returns (bool) {
        return _remove(set._inner, bytes32(uint(uint160(value))));
    }


    function contains(AddressSet storage set, address value) internal view returns (bool) {
        return _contains(set._inner, bytes32(uint(uint160(value))));
    }


    function length(AddressSet storage set) internal view returns (uint256) {
        return _length(set._inner);
    }


    function at(AddressSet storage set, uint256 index) internal view returns (address) {
        return address(uint160(uint(_at(set._inner, index))));
    }




    struct UintSet {
        Set _inner;
    }


    function add(UintSet storage set, uint256 value) internal returns (bool) {
        return _add(set._inner, bytes32(value));
    }


    function remove(UintSet storage set, uint256 value) internal returns (bool) {
        return _remove(set._inner, bytes32(value));
    }


    function contains(UintSet storage set, uint256 value) internal view returns (bool) {
        return _contains(set._inner, bytes32(value));
    }


    function length(UintSet storage set) internal view returns (uint256) {
        return _length(set._inner);
    }


    function at(UintSet storage set, uint256 index) internal view returns (uint256) {
        return uint256(_at(set._inner, index));
    }
}


contract Ownable {
  address public owner;


  event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);



  constructor()  {
    owner = msg.sender;
  }



  modifier onlyOwner() {
    require(msg.sender == owner);
    _;
  }



  function transferOwnership(address newOwner) onlyOwner public {
    require(newOwner != address(0));
    emit OwnershipTransferred(owner, newOwner);
    owner = newOwner;
  }
}


interface Token {
    function transferFrom(address, address, uint) external returns (bool);
    function transfer(address, uint) external returns (bool);
}

contract BSB_StakingSmartStakers is Ownable {
    using SafeMath for uint;
    using EnumerableSet for EnumerableSet.AddressSet;

    event RewardsTransferred(address holder, uint amount);
    event RewardsRestaked(address holder, uint amount);


    address public constant tokenDepositAddress = 0xA478A13242b64629bff309125770B69f75Bd77cb;


    uint public rewardRate = 52000;
    uint public constant rewardInterval = 365 days;


    uint public constant stakingFeeRate = 100;


    uint public constant unstakingFeeRate = 50;


    uint public constant unstakeTime = 90 days;


    uint public constant claimTime = 10 days;


    uint public constant maxPoolSize = 50000000000000000000000;
    uint public availablePoolSize = 50000000000000000000000;


    uint public constant totalRewards = 200000000000000000000000; 

    uint public totalClaimedRewards = 0;
    uint public totalDeposited = 0; 
    bool public ended ;

    EnumerableSet.AddressSet private holders;

    mapping (address => uint) public depositedTokens;
    mapping (address => uint) public maxDepositedTokens;
    mapping (address => uint) public stakingTime; 
    mapping (address => uint) public firstTime; 
    mapping (address => uint) public lastClaimedTime; 
    mapping (address => uint) public progressiveTime; 
    mapping (address => uint) public totalEarnedTokens;

    mapping (address => uint) public rewardEnded;


    mapping (address => uint) public alreadyProgUnstaked; 
    mapping (address => uint) public amountPerInterval;
    uint public number_intervals = 4;
    uint public duration_interval = 30 days;


    uint extraAPY = 10400; 


    uint percent_claim = 2; 
    mapping (address => uint) public unclaimed;

    uint public endTime;




    function end() public onlyOwner returns (bool){
        require(!ended, "Staking already ended");
        address _aux;

        for(uint i = 0; i < holders.length(); i = i.add(1)){
            _aux = holders.at(i);
            rewardEnded[_aux] = getPendingRewards(_aux);
            unclaimed[_aux] = 0;
            stakingTime[_aux] = block.timestamp;
            progressiveTime[_aux] = block.timestamp;
            alreadyProgUnstaked[_aux] = 0;
            amountPerInterval[_aux] = depositedTokens[_aux].div(number_intervals);
        }

        ended = true;
        endTime = block.timestamp;
        return true;
    }

    function getRewardsLeft() public view returns (uint){

        uint _res;
        if(ended){
            _res = 0;
        }else{
            uint totalPending;

            for(uint i = 0; i < holders.length(); i = i.add(1)){
                totalPending = totalPending.add(getPendingRewards(holders.at(i)));
            }
            if(totalRewards > totalClaimedRewards.add(totalPending)){
                _res = totalRewards.sub(totalClaimedRewards).sub(totalPending);
            }else{
                _res = 0;
            }

        }

        return _res;
    }

    function updateAccount(address account, bool _restake, bool _withdraw) private returns (bool){
        uint pendingDivs = getPendingRewards(account);
        uint toSend = pendingDivs;

        if(depositedTokens[account].mul(percent_claim).div(100) < pendingDivs){
            toSend = depositedTokens[account].mul(percent_claim).div(100);
        }

        if (pendingDivs > 0) {
            if(ended){ 
                if(!_withdraw){

                    if(depositedTokens[account] == 0){

                        if( maxDepositedTokens[account].mul(percent_claim).div(100) > pendingDivs ){
                            toSend = pendingDivs;
                        }else{
                            toSend = maxDepositedTokens[account].mul(percent_claim).div(100);
                        }
                    }
                     rewardEnded[account] = rewardEnded[account].sub(toSend);
                     require(Token(tokenDepositAddress).transfer(account, toSend), "Could not transfer tokens.");
                     totalEarnedTokens[account] = totalEarnedTokens[account].add(toSend);
                     totalClaimedRewards = totalClaimedRewards.add(toSend);
                }

            }else{

                if(_restake){ 
                    require(pendingDivs <= availablePoolSize, "No spot available");
                    depositedTokens[account] = depositedTokens[account].add(pendingDivs);

                    unclaimed[account] = 0;

                    if(depositedTokens[account] > maxDepositedTokens[account]){
                        maxDepositedTokens[account] = depositedTokens[account];
                    } 
                    availablePoolSize = availablePoolSize.sub(pendingDivs);
                    totalDeposited = totalDeposited.add(pendingDivs);
                    totalEarnedTokens[account] = totalEarnedTokens[account].add(pendingDivs);
                    totalClaimedRewards = totalClaimedRewards.add(pendingDivs);
                }else if(_withdraw){ 
                    unclaimed[account] = pendingDivs;

                }else{ 
                    if(depositedTokens[account] == 0){

                        if( maxDepositedTokens[account].mul(percent_claim).div(100) > pendingDivs ){
                            toSend = pendingDivs;
                        }else{
                            toSend = maxDepositedTokens[account].mul(percent_claim).div(100);
                        }
                    }
                    uint toUnclaimed = 0;
                    uint subUnclaimed = 0;
                    uint pendingWithoutUnclaimed = getOnlyPendingRewards(account);
                    if(toSend > pendingWithoutUnclaimed){
                        subUnclaimed = toSend.sub(pendingWithoutUnclaimed);
                        toUnclaimed = 0;
                    }else{
                        toUnclaimed = pendingWithoutUnclaimed.sub(toSend);
                        subUnclaimed = 0;
                    }

                    unclaimed[account] = unclaimed[account].add(toUnclaimed).sub(subUnclaimed);
                    require(Token(tokenDepositAddress).transfer(account, toSend), "Could not transfer tokens.");
                    totalEarnedTokens[account] = totalEarnedTokens[account].add(toSend);
                    totalClaimedRewards = totalClaimedRewards.add(toSend);
                }
            }    
        }
        lastClaimedTime[account] = block.timestamp;
        return true;
    }

    function getAPY(address _staker) public view returns(uint){
        uint apy = rewardRate;
        if(block.timestamp.sub(firstTime[_staker]) > unstakeTime && alreadyProgUnstaked[_staker] == 0 && !ended){
            apy = apy.add(extraAPY);
        }
        return apy;
    }

    function getPendingRewards(address _holder) public view returns (uint) { 
        if (!holders.contains(_holder)) return 0;
        if (depositedTokens[_holder] == 0 && unclaimed[_holder] == 0 && !ended) return 0;
        uint pendingDivs;
        if(!ended){
             uint timeDiff = block.timestamp.sub(lastClaimedTime[_holder]);
             uint stakedAmount = depositedTokens[_holder];


             uint apy = getAPY(_holder);

             pendingDivs = stakedAmount
                                .mul(apy) 
                                .mul(timeDiff)
                                .div(rewardInterval)
                                .div(1e4);

             pendingDivs = pendingDivs.add(unclaimed[_holder]);

        }else{
            pendingDivs = rewardEnded[_holder];
        }

        return pendingDivs;
    }

    function getOnlyPendingRewards(address _holder) internal view returns (uint) { 
        if (!holders.contains(_holder)) return 0;
        if (depositedTokens[_holder] == 0 || ended) return 0;
        uint pendingDivs;
        if(!ended){
             uint timeDiff = block.timestamp.sub(lastClaimedTime[_holder]);
             uint stakedAmount = depositedTokens[_holder];


             uint apy = getAPY(_holder);

             pendingDivs = stakedAmount
                                .mul(apy) 
                                .mul(timeDiff)
                                .div(rewardInterval)
                                .div(1e4);

        }else{
            pendingDivs = 0;
        }

        return pendingDivs;
    }

    function getNumberOfHolders() public view returns (uint) {
        return holders.length();
    }

    function deposit(uint amountToStake) public returns (bool){
        require(!ended, "Staking has ended");
        require(getRewardsLeft() > 0, "No rewards left");
        require(amountToStake > 0, "Cannot deposit 0 Tokens");

        require(Token(tokenDepositAddress).transferFrom(msg.sender, address(this), amountToStake), "Insufficient Token Allowance");


        require(updateAccount(msg.sender, true, false), "Error updating account");

        uint fee = amountToStake.mul(stakingFeeRate).div(1e4);
        uint amountAfterFee = amountToStake.sub(fee);
        require(amountAfterFee <= availablePoolSize, "No space available");
        require(Token(tokenDepositAddress).transfer(owner, fee), "Could not transfer deposit fee.");

        depositedTokens[msg.sender] = depositedTokens[msg.sender].add(amountAfterFee);
        if(depositedTokens[msg.sender] > maxDepositedTokens[msg.sender]){
            maxDepositedTokens[msg.sender] = depositedTokens[msg.sender];
        } 
        availablePoolSize = availablePoolSize.sub(amountAfterFee);
        totalDeposited = totalDeposited.add(amountAfterFee);

        if (!holders.contains(msg.sender)) {
            holders.add(msg.sender);
            firstTime[msg.sender] = block.timestamp;

        }


        amountPerInterval[msg.sender] = 0;
        if(alreadyProgUnstaked[msg.sender] > 0){
            firstTime[msg.sender] = block.timestamp;
        } 

        alreadyProgUnstaked[msg.sender] = 0;

        stakingTime[msg.sender] = block.timestamp;
        return true;
    }


    function getMaxAmountWithdrawable(address _staker) public view returns(uint){
        uint _res = 0;
        if(block.timestamp.sub(stakingTime[msg.sender]) < unstakeTime && !ended && alreadyProgUnstaked[_staker] == 0){
            _res = 0;
        }else if(alreadyProgUnstaked[_staker] == 0 && !ended){

            if(block.timestamp.sub(stakingTime[msg.sender]) > unstakeTime){
                _res = depositedTokens[_staker].div(number_intervals);
            }

        }else{
            uint _time = progressiveTime[_staker];

            if(block.timestamp < _time.add(duration_interval)){
                _res = 0;
            }else{


                uint _numIntervals = (block.timestamp.sub(_time)).div(duration_interval);

                if(_numIntervals == 0){
                    return 0;
                }
                if(!ended){
                    _numIntervals = _numIntervals.add(1);
                }


                if(_numIntervals > number_intervals){
                    _numIntervals = number_intervals;
                }

                if(_numIntervals.mul(amountPerInterval[_staker]) > alreadyProgUnstaked[_staker]){
                    _res = _numIntervals.mul(amountPerInterval[_staker]).sub(alreadyProgUnstaked[_staker]);
                }else{
                    _res = 0;
                }
            }


        }

        return _res;
    }


    function withdraw2(uint amountToWithdraw) public returns (bool){
        require(holders.contains(msg.sender), "Not a staker");
        require(amountToWithdraw <= getMaxAmountWithdrawable(msg.sender), "Maximum reached");
        require(alreadyProgUnstaked[msg.sender] > 0 || ended, "Use withdraw first");

        alreadyProgUnstaked[msg.sender] = alreadyProgUnstaked[msg.sender].add(amountToWithdraw);

        uint fee = amountToWithdraw.mul(unstakingFeeRate).div(1e4);
        uint amountAfterFee = amountToWithdraw.sub(fee);

        updateAccount(msg.sender, false, true);

        require(Token(tokenDepositAddress).transfer(owner, fee), "Could not transfer withdraw fee.");
        require(Token(tokenDepositAddress).transfer(msg.sender, amountAfterFee), "Could not transfer tokens.");

        depositedTokens[msg.sender] = depositedTokens[msg.sender].sub(amountToWithdraw);
        availablePoolSize = availablePoolSize.add(amountToWithdraw);
        totalDeposited = totalDeposited.sub(amountToWithdraw);

        if (holders.contains(msg.sender) && depositedTokens[msg.sender] == 0 && getPendingRewards(msg.sender) == 0) {
            holders.remove(msg.sender);
            firstTime[msg.sender] = 0;
        }
        return true;
    }


    function withdraw(uint amountToWithdraw) public returns (bool){
        require(holders.contains(msg.sender), "Not a staker");
        require(alreadyProgUnstaked[msg.sender] == 0 && !ended , "Use withdraw2 function");
        amountPerInterval[msg.sender] = depositedTokens[msg.sender].div(number_intervals);
        require(depositedTokens[msg.sender].div(number_intervals) >= amountToWithdraw, "Invalid amount to withdraw");
        alreadyProgUnstaked[msg.sender] = amountToWithdraw;
        require(block.timestamp.sub(stakingTime[msg.sender]) > unstakeTime || ended, "You recently staked, please wait before withdrawing.");



        updateAccount(msg.sender, false, true);

        uint fee = amountToWithdraw.mul(unstakingFeeRate).div(1e4);
        uint amountAfterFee = amountToWithdraw.sub(fee);

        require(Token(tokenDepositAddress).transfer(owner, fee), "Could not transfer withdraw fee.");
        require(Token(tokenDepositAddress).transfer(msg.sender, amountAfterFee), "Could not transfer tokens.");

        depositedTokens[msg.sender] = depositedTokens[msg.sender].sub(amountToWithdraw);
        availablePoolSize = availablePoolSize.add(amountToWithdraw);
        totalDeposited = totalDeposited.sub(amountToWithdraw);

        progressiveTime[msg.sender] = block.timestamp;

        return true;
    }

    function getTimeToWithdraw(address _staker) public view returns (uint){
        if(getMaxAmountWithdrawable(_staker) != 0) return 0;

        uint _res = 0;
        uint _time = stakingTime[_staker];
        if(alreadyProgUnstaked[_staker] == 0 && !ended ){

            if(block.timestamp <= _time.add(unstakeTime)){
                _res = _time.add(unstakeTime).sub(block.timestamp);
            }

        }else{
            _time = progressiveTime[_staker];

            for(uint i = 1; i <= number_intervals; i = i.add(1)){
                if(block.timestamp < _time.add(duration_interval.mul(i))){
                    _res = _time.add(duration_interval.mul(i)).sub(block.timestamp);
                    break;
                }
            }

        }
        return _res;
    }

    function getTimeToClaim(address _staker) public view returns (uint){
        uint _res = 0;

        if(lastClaimedTime[_staker].add(claimTime) > block.timestamp){
            _res = lastClaimedTime[_staker].add(claimTime).sub(block.timestamp);
        }

        return _res;
    }

    function claimDivs() public  returns (bool){
        require(holders.contains(msg.sender), "Not a staker");
        require(block.timestamp.sub(lastClaimedTime[msg.sender]) > claimTime, "Not yet");
        updateAccount(msg.sender, false, false);
        return true;
    }

    function getStakersList(uint startIndex, uint endIndex) public view returns (address[] memory stakers, uint[] memory stakingTimestamps,  uint[] memory lastClaimedTimeStamps, uint[] memory stakedTokens) {
        require (startIndex < endIndex);

        uint length = endIndex.sub(startIndex);
        address[] memory _stakers = new address[](length);
        uint[] memory _stakingTimestamps = new uint[](length);
        uint[] memory _lastClaimedTimeStamps = new uint[](length);
        uint[] memory _stakedTokens = new uint[](length);

        for (uint i = startIndex; i < endIndex; i = i.add(1)) {
            address staker = holders.at(i);
            uint listIndex = i.sub(startIndex);
            _stakers[listIndex] = staker;
            _stakingTimestamps[listIndex] = stakingTime[staker];
            _lastClaimedTimeStamps[listIndex] = lastClaimedTime[staker];
            _stakedTokens[listIndex] = depositedTokens[staker];
        }

        return (_stakers, _stakingTimestamps, _lastClaimedTimeStamps, _stakedTokens);
    }


    function transferAnyERC20Tokens(address _tokenAddr, address _to, uint _amount) public onlyOwner  returns (bool){
        require (_tokenAddr != tokenDepositAddress, "Cannot Transfer Out this token");
        Token(_tokenAddr).transfer(_to, _amount);
        return true;
    }

    function getClaimableAmount(address account) public view returns (uint){
        uint pendingDivs = getPendingRewards(account);
        uint toSend = pendingDivs;

        if(depositedTokens[account].mul(percent_claim).div(100) < pendingDivs){
            toSend = depositedTokens[account].mul(percent_claim).div(100);
        }

        if (pendingDivs > 0) {
            if(ended){ 
                    if(depositedTokens[account] == 0){

                        if( maxDepositedTokens[account].mul(percent_claim).div(100) > pendingDivs ){
                            toSend = pendingDivs;
                        }else{
                            toSend = maxDepositedTokens[account].mul(percent_claim).div(100);
                        }
                    }

            }else{
                if(depositedTokens[account] == 0){

                    if( maxDepositedTokens[account].mul(percent_claim).div(100) > pendingDivs ){
                        toSend = pendingDivs;
                    }else{
                        toSend = maxDepositedTokens[account].mul(percent_claim).div(100);
                    }
                }
            }    
        }
        return toSend;
    }

}

pragma solidity 0.8.4;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC721/utils/ERC721Holder.sol";
import "./libs/SafeBEP20.sol";
import "./BullToken.sol";
import "./RewardDistribution.sol";
import "./interfaces/IBullReferral.sol";
import "./interfaces/IBullNFT.sol";








contract MasterChef is ERC721Holder, Ownable, ReentrancyGuard {
    using SafeMath for uint256;
    using SafeBEP20 for IBEP20;


    struct UserInfo {
        uint256 amount;         
        uint256 rewardDebt;     
        uint256 rewardLockedUp;  
        uint256 strength; 
        uint256 nftId; 
        uint64 nextHarvestUntil; 
        uint64 lastHarvest; 

    }


    struct PoolInfo {
        IBEP20 lpToken;            
        uint256 lastRewardBlock;   
        uint256 accBullPerShare;  
        uint256 totalStrength;     
        uint32 allocPoint;        
        uint32 harvestInterval;   
        uint16 depositFeeBP;       
    }


    BullToken public bull;

    address public devAddress;

    address public feeAddress;

    uint128 public bullPerBlock;

    uint256 public constant MAXIMUM_HARVEST_INTERVAL = 7 days;


    PoolInfo[] public poolInfo;

    mapping(uint16 => mapping(address => UserInfo)) public userInfo;

    uint256 public totalAllocPoint = 0;

    uint256 public startBlock;

    uint256 public totalLockedUpRewards;

    RewardDistribution public rewardDistribution;

    IBullReferral public bullReferral;

    uint16 public referralCommissionRate = 200;

    uint16 public constant MAXIMUM_REFERRAL_COMMISSION_RATE = 1000;

    uint8 thePersistentBull = 4;
    uint8 bullseye = 5;
    uint8 missedBull = 6;
    uint8 bullFarmer = 8;

    uint32 constant private TWO_DAYS = 2 days;  
    uint256 constant private MINIMUM_REWARDS_FOR_NFT = 100 * 10**18;

    IBullNFT public bullNFT;

    event Deposit(address indexed user, uint256 indexed pid, uint256 amount);
    event Withdraw(address indexed user, uint256 indexed pid, uint256 amount);
    event EmergencyWithdraw(address indexed user, uint256 indexed pid, uint256 amount);
    event DepositNFT(address indexed user, uint256 indexed pid, uint256 nftId);
    event WithdrawNFT(address indexed user, uint256 indexed pid, uint256 nftId);
    event EmissionRateUpdated(address indexed caller, uint256 previousAmount, uint256 newAmount);
    event ReferralCommissionPaid(address indexed user, address indexed referrer, uint256 commissionAmount);
    event RewardLockedUp(address indexed user, uint256 indexed pid, uint256 amountLockedUp);
    event RewardPaid(address indexed user, uint256 indexed pid, uint256 amountReward);

    constructor(
        BullToken _bull,
        IBullNFT _bullNFT,
        address _feeAddress,
        uint128 _bullPerBlock,
        uint256 _startBlock
    ) public {
        bull = _bull;
        bullNFT = _bullNFT;
        devAddress = msg.sender;
        feeAddress = _feeAddress;
        bullPerBlock = _bullPerBlock;
        startBlock = _startBlock;
    }


    function setRewardDistribution(RewardDistribution _rewardDistribution) external onlyOwner{
        rewardDistribution = _rewardDistribution;
    }


    function poolLength() external view returns (uint256) {
        return poolInfo.length;
    }


    mapping(IBEP20 => bool) public poolExistence;
    modifier nonDuplicated(IBEP20 _lpToken) {
        require(poolExistence[_lpToken] == false, "nonDuplicated: duplicated");
        _;
    }


    function add(uint32 _allocPoint, IBEP20 _lpToken, uint16 _depositFeeBP, uint32 _harvestInterval, bool _withRewards) public onlyOwner nonDuplicated(_lpToken) {
        require(_depositFeeBP <= 1500, "add: deposit fee can't be more than 15%");
        require(_harvestInterval <= MAXIMUM_HARVEST_INTERVAL, "add: invalid harvest interval");
        _massUpdatePools();
        uint256 lastRewardBlock = block.number > startBlock ? block.number : startBlock;
        totalAllocPoint = totalAllocPoint.add(_allocPoint);
        poolExistence[_lpToken] = true;
        poolInfo.push(PoolInfo({
            lpToken: _lpToken,
            allocPoint: _allocPoint,
            lastRewardBlock: lastRewardBlock,
            accBullPerShare: 0,
            depositFeeBP: _depositFeeBP,
            harvestInterval: _harvestInterval,
            totalStrength: 0
        }));
        if(_withRewards){
            uint16 pid = uint16(poolInfo.length - 1);
            rewardDistribution.add(_lpToken, pid);
        }   
    }


    function set(uint256 _pid, uint32 _allocPoint, uint16 _depositFeeBP, uint32 _harvestInterval) public onlyOwner {
        require(_depositFeeBP <= 10000, "set: invalid deposit fee basis points");
        require(_harvestInterval <= MAXIMUM_HARVEST_INTERVAL, "set: invalid harvest interval");
        _massUpdatePools();
        totalAllocPoint = totalAllocPoint.sub(poolInfo[_pid].allocPoint).add(_allocPoint);
        poolInfo[_pid].allocPoint = _allocPoint;
        poolInfo[_pid].depositFeeBP = _depositFeeBP;
        poolInfo[_pid].harvestInterval = _harvestInterval;
    }


    function pendingBull(uint16 _pid, address _user) external view returns (uint256) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_user];
        uint256 accBullPerShare = pool.accBullPerShare;
        if (block.number > pool.lastRewardBlock && pool.totalStrength != 0) {
            uint256 multiplier = block.number.sub(pool.lastRewardBlock);
            uint256 bullReward = multiplier.mul(bullPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
            accBullPerShare = accBullPerShare.add(bullReward.mul(1e12).div(pool.totalStrength));
        }
        uint256 pending = user.strength.mul(accBullPerShare).div(1e12).sub(user.rewardDebt);
        return pending.add(user.rewardLockedUp);
    }


    function canHarvest(uint16 _pid, address _user) public view returns (bool) {
        UserInfo storage user = userInfo[_pid][_user];
        return block.timestamp >= user.nextHarvestUntil;
    }


    function _massUpdatePools() private {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            _updatePool(pid);
        }
    }


    function _updatePool(uint256 _pid) private {
        PoolInfo storage pool = poolInfo[_pid];
        if (block.number <= pool.lastRewardBlock) {
            return;
        }
        if (pool.totalStrength == 0 || pool.allocPoint == 0) {
            pool.lastRewardBlock = block.number;
            return;
        }
        uint256 multiplier = block.number.sub(pool.lastRewardBlock);
        uint256 bullReward = multiplier.mul(bullPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
        bull.mint(devAddress, bullReward.div(10));
        bull.mint(address(this), bullReward);
        pool.accBullPerShare = pool.accBullPerShare.add(bullReward.mul(1e12).div(pool.totalStrength));
        pool.lastRewardBlock = block.number;
    }


    function deposit(uint16 _pid, uint256 _amount, address _referrer) public nonReentrant {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        _updatePool(_pid);
        if (_amount > 0 && address(bullReferral) != address(0) && _referrer != address(0) && _referrer != msg.sender) {
            bullReferral.recordReferral(msg.sender, _referrer);
        }
        payOrLockupPendingBull(_pid);
        if (_amount > 0) {
            pool.lpToken.safeTransferFrom(address(msg.sender), address(this), _amount);
            if (address(pool.lpToken) == address(bull)) {
                uint256 transferTax = _amount.mul(bull.transferTaxRate()).div(10000);
                _amount = _amount.sub(transferTax);
            }
            if (pool.depositFeeBP > 0) {
                uint256 depositFee = _amount.mul(pool.depositFeeBP).div(10000);
                pool.lpToken.safeTransfer(feeAddress, depositFee);
                user.amount = user.amount.add(_amount).sub(depositFee);
            } else {
                user.amount = user.amount.add(_amount);
                if(rewardDistribution.poolExistence(_pid)){
                    rewardDistribution.incrementBalance(_pid, _amount, msg.sender);
                }
            }
        }
        _updateStrength(_pid);
        user.rewardDebt = user.strength.mul(pool.accBullPerShare).div(1e12);
        emit Deposit(msg.sender, _pid, _amount);
    }


    function withdraw(uint16 _pid, uint256 _amount) public nonReentrant {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        require(user.amount >= _amount, "withdraw: not good");
        _updatePool(_pid);
        payOrLockupPendingBull(_pid);
        if (_amount > 0) {
            user.amount = user.amount.sub(_amount);
            pool.lpToken.safeTransfer(address(msg.sender), _amount);
            if(rewardDistribution.poolExistence(_pid)){
                rewardDistribution.reduceBalance(_pid, _amount, msg.sender);
            }
        }
        _updateStrength(_pid);
        user.rewardDebt = user.strength.mul(pool.accBullPerShare).div(1e12);
        emit Withdraw(msg.sender, _pid, _amount);
    }


    function emergencyWithdraw(uint16 _pid) public nonReentrant {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        uint256 amount = user.amount;
        user.amount = 0;
        user.strength = 0;
        user.rewardDebt = 0;
        user.rewardLockedUp = 0;
        user.nextHarvestUntil = 0;
        pool.lpToken.safeTransfer(address(msg.sender), amount);
        emit EmergencyWithdraw(msg.sender, _pid, amount);
    }


    function safeBullTransfer(address _to, uint256 _amount) internal {
        uint256 bullBal = bull.balanceOf(address(this));
        bool transferSuccess = false;
        if (_amount > bullBal) {
            transferSuccess = bull.transfer(_to, bullBal);
        } else {
            transferSuccess = bull.transfer(_to, _amount);
        }
        require(transferSuccess, "safeBullTransfer: transfer failed");
    }


    function payOrLockupPendingBull(uint16 _pid) internal {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];

        uint256 harvestInterval = pool.harvestInterval;

        if(user.nftId > 0){
            uint256 boostId = bullNFT.getBoost(user.nftId);
            if(boostId == thePersistentBull){
                harvestInterval = harvestInterval > bullNFT.getBonus(boostId) ? harvestInterval.sub(bullNFT.getBonus(boostId)) : 0;
            }
        }

        if (user.nextHarvestUntil == 0) {
            user.nextHarvestUntil = uint64(block.timestamp.add(harvestInterval));
        }

        uint256 pending = user.strength.mul(pool.accBullPerShare).div(1e12).sub(user.rewardDebt);
        if (canHarvest(_pid, msg.sender)) {
            if (pending > 0 || user.rewardLockedUp > 0) {
                uint256 totalRewards = pending.add(user.rewardLockedUp);


                totalLockedUpRewards = totalLockedUpRewards.sub(user.rewardLockedUp);
                user.rewardLockedUp = 0;
                user.nextHarvestUntil = uint64(block.timestamp.add(harvestInterval));


                safeBullTransfer(msg.sender, totalRewards);
                if(totalRewards >= MINIMUM_REWARDS_FOR_NFT){
                    checkMintNFT(_pid, msg.sender);
                }
                if(rewardDistribution.poolExistence(_pid)){
                    rewardDistribution.harvest(_pid, msg.sender);
                }
                payReferralCommission(msg.sender, totalRewards);
                emit RewardPaid(msg.sender, _pid, totalRewards);
            }
        } else if (pending > 0) {
            user.rewardLockedUp = user.rewardLockedUp.add(pending);
            totalLockedUpRewards = totalLockedUpRewards.add(pending);
            emit RewardLockedUp(msg.sender, _pid, pending);
        }
        user.lastHarvest = uint64(block.timestamp);
    }


    function checkMintNFT(uint16 _pid, address _user) private {
        UserInfo storage user = userInfo[_pid][_user];
        if(bullNFT.canMint(bullFarmer) && bullNFT.getAuthorizedMiner(bullFarmer) == address(this)){
            if(block.timestamp.sub(user.lastHarvest) >= TWO_DAYS){
                bullNFT.mint(bullFarmer, msg.sender);
            }
        }
    }


    function depositNFT(uint16 _pid, uint256 _nftId) external {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];

        _updatePool(_pid);
        payOrLockupPendingBull(_pid);

        uint256 boostId = bullNFT.getBoost(_nftId);
        if (user.nftId == 0 &&
            (boostId == bullseye ||
             boostId == missedBull ||
             boostId == bullFarmer)
             ){
            bullNFT.safeTransferFrom(address(msg.sender), address(this), _nftId);
            user.nftId = _nftId;
        }
        _updateStrength(_pid);	

        user.rewardDebt = user.strength.mul(pool.accBullPerShare).div(1e12);
        emit DepositNFT(msg.sender, _pid, _nftId);
    }


    function withdrawNFT(uint16 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        require(user.nftId > 0, "user has no NFT");

        _updatePool(_pid);
        payOrLockupPendingBull(_pid);

        uint256 _nftId = user.nftId;
        bullNFT.transferFrom(address(this), address(msg.sender), user.nftId);
        user.nftId = 0;
        _updateStrength(_pid);

        user.rewardDebt = user.strength.mul(pool.accBullPerShare).div(1e12);
        emit WithdrawNFT(msg.sender, _pid, _nftId);
    }


    function _updateStrength(uint16 _pid) private {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];

        uint256 oldStrength = user.strength;

        user.strength = user.amount;

        if (user.nftId > 0) {
            uint bonus = bullNFT.getBonus(user.nftId);
            user.strength = user.strength.add(user.strength.mul(bonus).div(10000));
        }

        pool.totalStrength = pool.totalStrength.add(user.strength).sub(oldStrength);
    }


    function setDevAddress(address _devAddress) public {
        require(msg.sender == devAddress, "setDevAddress: FORBIDDEN");
        require(_devAddress != address(0), "setDevAddress: ZERO");
        devAddress = _devAddress;
    }


    function setFeeAddress(address _feeAddress) public {
        require(msg.sender == feeAddress, "setFeeAddress: FORBIDDEN");
        require(_feeAddress != address(0), "setFeeAddress: ZERO");
        feeAddress = _feeAddress;
    }


    function updateEmissionRate(uint128 _bullPerBlock) public onlyOwner {
        _massUpdatePools();
        bullPerBlock = _bullPerBlock;
        emit EmissionRateUpdated(msg.sender, bullPerBlock, _bullPerBlock);
    }


    function setBullReferral(IBullReferral _bullReferral) public onlyOwner {
        bullReferral = _bullReferral;
    }


    function setReferralCommissionRate(uint16 _referralCommissionRate) public onlyOwner {
        require(_referralCommissionRate <= MAXIMUM_REFERRAL_COMMISSION_RATE, "setReferralCommissionRate: invalid referral commission rate basis points");
        referralCommissionRate = _referralCommissionRate;
    }


    function payReferralCommission(address _user, uint256 _pending) internal {
        if (address(bullReferral) != address(0) && referralCommissionRate > 0) {
            address referrer = bullReferral.getReferrer(_user);
            uint256 commissionAmount = _pending.mul(referralCommissionRate).div(10000);

            if (referrer != address(0) && commissionAmount > 0) {
                bull.mint(referrer, commissionAmount);
                bullReferral.recordReferralCommission(referrer, commissionAmount);
                emit ReferralCommissionPaid(_user, referrer, commissionAmount);
            }
        }
    }
}

