import '@openzeppelin/contracts/interfaces/IERC20.sol';
import '@openzeppelin/contracts/utils/math/SafeMath.sol';
import './OKLGProduct.sol';


contract OKLGPasswordManager is OKLGProduct {
  using SafeMath for uint256;

  struct AccountInfo {
    string id;
    uint256 timestamp;
    string iv;
    string ciphertext;
    bool isDeleted;
  }

  mapping(address => mapping(string => uint256)) public userAccountIdIndexes;


  mapping(address => AccountInfo[]) public userAccounts;

  constructor(address _tokenAddress, address _spendAddress)
    OKLGProduct(uint8(2), _tokenAddress, _spendAddress)
  {}

  function getAllAccounts(address _userAddy)
    external
    view
    returns (AccountInfo[] memory)
  {
    return userAccounts[_userAddy];
  }

  function getAccountById(string memory _id)
    external
    view
    returns (AccountInfo memory)
  {
    AccountInfo[] memory _userInfo = userAccounts[msg.sender];

    for (uint256 _i = 0; _i < _userInfo.length; _i++) {
      if (_compareStr(_userInfo[_i].id, _id)) {
        return _userInfo[_i];
      }
    }
    return
      AccountInfo({
        id: '',
        timestamp: 0,
        iv: '',
        ciphertext: '',
        isDeleted: false
      });
  }

  function updateAccountById(
    string memory _id,
    string memory _newIv,
    string memory _newAccountData
  ) external returns (bool) {
    AccountInfo[] memory _userInfo = userAccounts[msg.sender];
    uint256 _idx = userAccountIdIndexes[msg.sender][_id];
    require(
      _compareStr(_id, _userInfo[_idx].id),
      'the ID provided does not match the account stored.'
    );
    userAccounts[msg.sender][_idx].iv = _newIv;
    userAccounts[msg.sender][_idx].timestamp = block.timestamp;
    userAccounts[msg.sender][_idx].ciphertext = _newAccountData;
    return true;
  }

  function addAccount(
    string memory _id,
    string memory _iv,
    string memory _ciphertext
  ) external payable {
    _payForService(0);

    require(
      userAccountIdIndexes[msg.sender][_id] == 0,
      'this ID is already being used, the account should be updated instead'
    );
    userAccountIdIndexes[msg.sender][_id] = userAccounts[msg.sender].length;

    userAccounts[msg.sender].push(
      AccountInfo({
        id: _id,
        timestamp: block.timestamp,
        iv: _iv,
        ciphertext: _ciphertext,
        isDeleted: false
      })
    );
  }

  function bulkAddAccounts(AccountInfo[] memory accounts) external payable {
    require(
      accounts.length >= 5,
      'you need a minimum of 5 accounts to add in bulk at a 50% discount service cost'
    );
    _payForService(0);

    for (uint256 _i = 0; _i < accounts.length; _i++) {
      AccountInfo memory _account = accounts[_i];
      userAccounts[msg.sender].push(
        AccountInfo({
          id: _account.id,
          timestamp: block.timestamp,
          iv: _account.iv,
          ciphertext: _account.ciphertext,
          isDeleted: false
        })
      );
    }
  }

  function deleteAccount(string memory _id) external returns (bool) {
    AccountInfo[] memory _userInfo = userAccounts[msg.sender];
    uint256 _idx = userAccountIdIndexes[msg.sender][_id];
    require(
      _compareStr(_id, _userInfo[_idx].id),
      'the ID provided does not match the account stored.'
    );
    userAccounts[msg.sender][_idx].timestamp = block.timestamp;
    userAccounts[msg.sender][_idx].isDeleted = true;
    return true;
  }

  function _compareStr(string memory a, string memory b)
    private
    pure
    returns (bool)
  {
    return (keccak256(abi.encodePacked((a))) ==
      keccak256(abi.encodePacked((b))));
  }
}

pragma solidity 0.5.11;

import "../../proxies/smart-wallet/UpgradeBeaconProxyV1.sol";
import "../../../interfaces/DharmaSmartWalletFactoryV1Interface.sol";
import "../../../interfaces/DharmaSmartWalletInitializer.sol";



contract DharmaSmartWalletFactoryV1 is DharmaSmartWalletFactoryV1Interface {

  DharmaSmartWalletInitializer private _INITIALIZER;


  function newSmartWallet(
    address userSigningKey
  ) external returns (address wallet) {

    bytes memory initializationCalldata = abi.encodeWithSelector(
      _INITIALIZER.initialize.selector,
      userSigningKey
    );


    wallet = _deployUpgradeBeaconProxyInstance(initializationCalldata);


    emit SmartWalletDeployed(wallet, userSigningKey);
  }


  function getNextSmartWallet(
    address userSigningKey
  ) external view returns (address wallet) {

    bytes memory initializationCalldata = abi.encodeWithSelector(
      _INITIALIZER.initialize.selector,
      userSigningKey
    );


    wallet = _computeNextAddress(initializationCalldata);
  }


  function _deployUpgradeBeaconProxyInstance(
    bytes memory initializationCalldata
  ) private returns (address upgradeBeaconProxyInstance) {

    bytes memory initCode = abi.encodePacked(
      type(UpgradeBeaconProxyV1).creationCode,
      abi.encode(initializationCalldata)
    );


    (uint256 salt, ) = _getSaltAndTarget(initCode);


    assembly {
      let encoded_data := add(0x20, initCode) 
      let encoded_size := mload(initCode)     
      upgradeBeaconProxyInstance := create2(  
        callvalue,                            
        encoded_data,                         
        encoded_size,                         
        salt                                  
      )


      if iszero(upgradeBeaconProxyInstance) {
        returndatacopy(0, 0, returndatasize)
        revert(0, returndatasize)
      }
    }
  }


  function _computeNextAddress(
    bytes memory initializationCalldata
  ) private view returns (address target) {

    bytes memory initCode = abi.encodePacked(
      type(UpgradeBeaconProxyV1).creationCode,
      abi.encode(initializationCalldata)
    );


    (, target) = _getSaltAndTarget(initCode);
  }



  function _getSaltAndTarget(
    bytes memory initCode
  ) private view returns (uint256 nonce, address target) {

    bytes32 initCodeHash = keccak256(initCode);


    nonce = 0;


    uint256 codeSize;


    while (true) {
      target = address(            
        uint160(                   
          uint256(                 
            keccak256(             
              abi.encodePacked(    
                bytes1(0xff),      
                address(this),     
                nonce,              
                initCodeHash       
              )
            )
          )
        )
      );


      assembly { codeSize := extcodesize(target) }


      if (codeSize == 0) {
        break;
      }


      nonce++;
    }
  }
}

